                            </td>

                            <td className="p-4">
                                {getScoreBadge(reporte.final_score)}
                            </td>

                            <td className="p-4">
                                {getStatusBadge(reporte.status)}
                            </td>

                            <td className="p-4 text-right">
                                <button
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        onViewReport(reporte.id);
                                    }}
                                    className="inline-flex items-center gap-2 px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-colors font-semibold text-sm"
                                >
                                    <Eye size={16} />
                                    Ver
                                </button>
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
}

import React, { useEffect, useState } from 'react';
import { Navigate, useLocation } from 'react-router-dom';
import { useAuth } from '../../hooks/useAuth';
import { LogOut } from 'lucide-react'; 
import { supabase } from '../../services/supabaseClient';

export const SetupGuard = ({ children }: { children: React.ReactNode }) => {
  const { orgId, user, loading: authLoading } = useAuth();
  const [isSetup, setIsSetup] = useState<boolean | null>(null);
  const [isChecking, setIsChecking] = useState(true);
  const location = useLocation();

  useEffect(() => {
    let intervalId: NodeJS.Timeout;

    const verifyStatus = async () => {
      // 1. Si todavía cargamos sesión, esperar.
      if (authLoading) return;

      // 2. CASO CRÍTICO: Usuario logueado pero sin OrgId (Race Condition del Trigger)
      if (user && !orgId) {
        // Mantenemos el estado de "Verificando" y reintentamos en 1 segundo
        // Esto da tiempo a que el Trigger de BD termine de crear la empresa
        console.log("⏳ Esperando creación de empresa...");
        return; 
      }

      // 3. Si no hay usuario ni org (Logout), dejamos de verificar y pasamos control
      if (!user) {
        setIsChecking(false);
        return;
      }

      // 4. Ya tenemos OrgId, verificamos el estado del Setup
      if (orgId) {
        try {
          const { data, error } = await supabase
            .from('organizations')
            .select('setup_completed')
            .eq('id', orgId)
            .single();

          if (data) {
            setIsSetup(data.setup_completed);
            setIsChecking(false); // ¡Listo! Dejamos de cargar
          }
        } catch (e) {
          console.error("Error verificando setup:", e);
          setIsChecking(false);
        }
      }
    };

    // Ejecutamos la verificación
    verifyStatus();

    // Si estamos en el caso crítico (user sin org), hacemos polling cada 1s
    if (user && !orgId && !authLoading) {
        intervalId = setInterval(() => {
            // Forzamos una recarga de la página si detectamos que esto tarda mucho
            // O idealmente llamamos a una función refreshSession() si existiera
            // Por simplicidad, recargamos la página tras 3 segundos para que useAuth tome los datos nuevos
            window.location.reload(); 
        }, 3000);
    }

    return () => {
        if (intervalId) clearInterval(intervalId);
    };
  }, [orgId, user, authLoading]);

  // PANTALLA DE CARGA (Mientras esperamos al Trigger)
  // PANTALLA DE CARGA (Modificada con botón de salida)
  if (authLoading || (user && !orgId) || isChecking) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-stone-50 p-4">
        <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-emerald-600 mb-4"></div>
        
        <p className="text-stone-500 font-medium animate-pulse mb-6">
            {!orgId ? "Configurando tu tostaduría..." : "Verificando cuenta..."}
        </p>

        {/* --- BOTÓN DE SALIDA DE EMERGENCIA --- */}
        <button 
            onClick={() => {
                supabase.auth.signOut();
                window.location.href = '/login';
            }}
            className="flex items-center gap-2 px-4 py-2 text-sm text-stone-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
        >
            <LogOut size={16} />
            Cancelar y Salir
        </button>
      </div>
    );
  }

  const onOnboardingPage = location.pathname === '/onboarding';

  // REDIRECCIONES (Semáforos)

  // A. Si ya configuró (TRUE) y quiere ver Onboarding -> Al Dashboard
  if (isSetup === true && onOnboardingPage) {
    return <Navigate to="/" replace />;
  }

  // B. Si NO ha configurado (FALSE) y quiere entrar al sistema -> Al Onboarding
  if (isSetup === false && !onOnboardingPage) {
    return <Navigate to="/onboarding" replace />;
  }

  // C. Todo correcto -> Renderizar contenido
  return <>{children}</>;
};

import React, { useEffect, useState } from 'react';
import { useAuth } from '../../hooks/useAuth';
import { supabase } from '../../services/supabaseClient';
import { Lock, CreditCard } from 'lucide-react';

export const SubscriptionGuard = ({ children }: { children: React.ReactNode }) => {
  const { orgId, loading: authLoading } = useAuth();
  const [loading, setLoading] = useState(true);
  const [status, setStatus] = useState<any>(null);

  useEffect(() => {
    if (orgId) checkSubscription();
  }, [orgId]);

  const checkSubscription = async () => {
    // CORRECCIÓN AQUÍ: 
    // Esta línea le asegura a TypeScript que si pasamos de aquí, orgId tiene valor.
    if (!orgId) return; 

    try {
      const { data, error } = await supabase
        .from('organizations')
        .select('plan, status, trial_ends_at, next_payment_date')
        .eq('id', orgId) // Ahora TypeScript sabe que orgId es 'string' seguro
        .single();

      if (error) throw error;
      setStatus(data);
    } catch (e) {
      console.error("Error verificando suscripción", e);
    } finally {
      setLoading(false);
    }
  };

  // Mientras carga la autenticación o la validación de suscripción
  if (authLoading || (loading && orgId)) {
    return <div className="h-screen bg-stone-50 flex items-center justify-center text-stone-500 font-bold animate-pulse">Verificando acceso...</div>;
  }

  // Si no cargó el estado (ej. error de red) o no hay orgId, dejamos pasar o mostramos loading
  if (!status) return <>{children}</>; 

  const now = new Date();
  const trialEnd = new Date(status.trial_ends_at);
  const paymentDue = status.next_payment_date ? new Date(status.next_payment_date) : null;

  // Lógica de Bloqueo
  let isLocked = false;
  let message = "";

  // Caso 1: Prueba Gratuita Vencida
  if (status.plan === 'free_trial' && now > trialEnd) {
    isLocked = true;
    message = "Tu periodo de prueba de 14 días ha finalizado.";
  }

  // Caso 2: Suscripción Vencida (Impago)
  if (status.status === 'past_due' || (status.status === 'active' && paymentDue && now > paymentDue)) {
    isLocked = true;
    message = "Tu suscripción ha vencido. Realiza el pago para continuar.";
  }

  // Si está bloqueado, mostramos pantalla de pago (Paywall)
  if (isLocked) {
    return (
      <div className="h-screen w-full bg-stone-900 flex items-center justify-center p-4">
        <div className="bg-white max-w-md w-full rounded-3xl p-8 text-center shadow-2xl animate-in fade-in zoom-in-95">
          <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-6 text-red-600 shadow-sm">
            <Lock size={32}/>
          </div>
          <h1 className="text-2xl font-bold text-stone-800 mb-2">Acceso Restringido</h1>
          <p className="text-stone-500 mb-8 leading-relaxed">{message}</p>
          
          <div className="bg-stone-50 p-4 rounded-xl border border-stone-200 text-left mb-6 shadow-inner">
            <h3 className="font-bold text-stone-800 flex items-center gap-2 mb-2 text-sm">
              <CreditCard size={16} className="text-emerald-600"/> Cómo reactivar:
            </h3>
            <p className="text-xs text-stone-600 mb-3">Realiza una transferencia o pago QR a la cuenta corporativa y envía el comprobante.</p>
            <div className="font-mono text-xs bg-white p-3 border border-stone-200 rounded-lg text-center text-stone-600">
              <p>Cuenta BNB: <span className="font-bold text-stone-800">123-456789</span></p>
              <p>NIT: <span className="font-bold text-stone-800">1020304050</span></p>
            </div>
          </div>

          <a 
            href="https://wa.me/591XXXXXXXX?text=Hola,%20quiero%20reactivar%20mi%20cuenta%20TraceBlend" 
            target="_blank" 
            rel="noreferrer"
            className="block w-full bg-stone-900 hover:bg-black text-white font-bold py-3.5 rounded-xl transition-all shadow-lg hover:shadow-xl transform hover:-translate-y-0.5"
          >
            Contactar Soporte para Pagar
          </a>
        </div>
      </div>
    );
  }

  // Acceso concedido
  return <>{children}</>;
};

