import React, { createContext, useState, useEffect, ReactNode } from 'react';
import { User } from '@supabase/supabase-js';
import { supabase } from '../services/supabaseClient';
import { getUserProfile, UserProfile } from '../services/authService';
import { getOrganizationSubscription, OrganizationSubscription } from '../services/subscriptionService';

// Definimos QUÉ datos expone nuestro contexto
export interface AuthContextType {
  user: User | null;
  profile: UserProfile | null;
  loading: boolean;
  signOut: () => Promise<void>;
  isAuthenticated: boolean;
  role: string | null;
  orgId: string | null;
  userName: string | null | undefined;
  subscription: OrganizationSubscription | null;
  planFeatures: string[];
}

// Creamos el contexto tipado (inicialmente undefined)
export const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider = ({ children }: { children: ReactNode }) => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  // Tipado explícito para el perfil
  const [profile, setProfile] = useState<UserProfile | null>(() => {
    const cached = localStorage.getItem('traceblend_profile');
    return cached ? JSON.parse(cached) : null;
  });

  // Estado para suscripción
  const [subscription, setSubscription] = useState<OrganizationSubscription | null>(null);

  const fetchProfile = async (userId: string) => {
    try {
      const data = await getUserProfile();
      if (data) {
        setProfile(data);
        localStorage.setItem('traceblend_profile', JSON.stringify(data));

        // Cargar información de suscripción
        if (data.organization_id) {
          const subscriptionData = await getOrganizationSubscription(data.organization_id);
          setSubscription(subscriptionData);
        }
      }
    } catch (e) {
      console.error("Auth: Error buscando perfil", e);
    }
  };

  useEffect(() => {
    let mounted = true;

    // Safety timer
    const safetyTimer = setTimeout(() => {
      if (mounted && loading) setLoading(false);
    }, 3000);

    const initializeAuth = async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession();

        if (session?.user) {
          setUser(session.user);
          if (!profile) {
            await fetchProfile(session.user.id);
          } else {
            fetchProfile(session.user.id);
          }
        } else {
          localStorage.removeItem('traceblend_profile');
        }
      } catch (error) {
        console.error("Auth Init Error:", error);
      } finally {
        if (mounted) {
          setLoading(false);
          clearTimeout(safetyTimer);
        }
      }
    };

    initializeAuth();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
      if (!mounted) return;
      if (event === 'INITIAL_SESSION') return;

      if (session?.user) {
        setUser(session.user);
        fetchProfile(session.user.id);
      } else {
        setUser(null);
        setProfile(null);
        localStorage.removeItem('traceblend_profile');
      }
      setLoading(false);
    });

    return () => {
      mounted = false;
      clearTimeout(safetyTimer);
      subscription.unsubscribe();
    };
  }, []);

  const signOut = async () => {
    try {
      await supabase.auth.signOut();
    } catch (e) { console.error(e); }

    setUser(null);
    setProfile(null);
    localStorage.removeItem('traceblend_profile');
    setLoading(false);
    window.location.href = '/login';
  };

  const value: AuthContextType = {
    user,
    profile,
    loading,
    signOut,
    isAuthenticated: !!user,
    role: profile?.role || null,
    orgId: profile?.organization_id || null,
    userName: profile?.first_name || user?.email,
    subscription,
    planFeatures: subscription?.available_features || []
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

import { useState, useRef } from 'react';
import { toast } from 'sonner';

export interface RoastDataPoint {
  time: number;
  bean: number;
  air: number;
}

export const useRoastLogger = () => {
  const [isConnected, setIsConnected] = useState(false);
  const [isRoasting, setIsRoasting] = useState(false);
  const [liveData, setLiveData] = useState<RoastDataPoint>({ time: 0, bean: 0, air: 0 });
  const [roastLog, setRoastLog] = useState<RoastDataPoint[]>([]);
  
  const portRef = useRef<any>(null);
  const readerRef = useRef<ReadableStreamDefaultReader | null>(null);
  const keepReadingRef = useRef(false);
  const startTimeRef = useRef<Date | null>(null);

  const connectToRoaster = async (baudRate = 115200) => {
    if (!("serial" in navigator)) {
      toast.error("Tu navegador no soporta Web Serial (Usa Chrome/Edge).");
      return;
    }

    try {
      // @ts-ignore: Web Serial types workaround
      const port = await navigator.serial.requestPort();
      await port.open({ baudRate });
      
      portRef.current = port;
      setIsConnected(true);
      toast.success("✅ Tostadora conectada");
      
      readLoop();
    } catch (err: any) {
      console.error(err);
      toast.error("Error al conectar: " + err.message);
    }
  };

  const readLoop = async () => {
    keepReadingRef.current = true;
    const textDecoder = new TextDecoderStream();
    // @ts-ignore
    const readableStreamClosed = portRef.current.readable.pipeTo(textDecoder.writable);
    const reader = textDecoder.readable.getReader();
    readerRef.current = reader;

    let buffer = "";

    try {
      while (keepReadingRef.current) {
        const { value, done } = await reader.read();
        if (done) break;
        
        buffer += value;
        const lines = buffer.split('\n');
        buffer = lines.pop() || ""; 

        for (const line of lines) {
          parseDataLine(line.trim());
        }
      }
    } catch (error) {
      console.error("Error de lectura:", error);
    } finally {
      reader.releaseLock();
    }
  };

  const parseDataLine = (line: string) => {
    if (!line) return;
    try {
      const parts = line.split(',');
      const beanTemp = parseFloat(parts[0]);
      const airTemp = parseFloat(parts[1]) || 0;

      if (!isNaN(beanTemp)) {
        const now = new Date();
        const timeSeconds = isRoasting && startTimeRef.current 
          ? (now.getTime() - startTimeRef.current.getTime()) / 1000 
          : 0;

        const dataPoint: RoastDataPoint = {
          time: parseFloat(timeSeconds.toFixed(1)),
          bean: beanTemp,
          air: airTemp
        };

        setLiveData(dataPoint);
        if (isRoasting) {
          setRoastLog(prev => [...prev, dataPoint]);
        }
      }
    } catch (e) { }
  };

  const startRoast = () => {
    setRoastLog([]);
    startTimeRef.current = new Date();
    setIsRoasting(true);
    toast.info("🔥 Tueste iniciado");
  };

  const stopRoast = () => {
    setIsRoasting(false);
    startTimeRef.current = null;
    toast.success("🏁 Tueste finalizado");
    return roastLog;
  };

  const disconnect = async () => {
    keepReadingRef.current = false;
    if (readerRef.current) await readerRef.current.cancel();
    if (portRef.current) await portRef.current.close();
    setIsConnected(false);
    setIsRoasting(false);
  };

  return {
    connectToRoaster, disconnect, startRoast, stopRoast,
    isConnected, isRoasting, liveData, roastLog
  };
};

import React, { useState } from 'react';
import { useAuth } from '../hooks/useAuth';
import { registrarApertura } from '../services/cajaService';
import { toast } from 'sonner';
import { PlayCircle, DollarSign, Loader2 } from 'lucide-react';

interface Props {
  onAperturaCompletada: () => void; // <-- Esta es la señal de éxito
}

export function AperturaCaja({ onAperturaCompletada }: Props) {
  const { orgId, user } = useAuth();
  const [monto, setMonto] = useState('');
  const [loading, setLoading] = useState(false);

  const handleApertura = async () => {
    if (!monto) return toast.warning("Ingresa el monto inicial");
    
    setLoading(true);
    try {
      // 1. Enviamos el dato a la base de datos
      await registrarApertura(Number(monto), orgId!, user!.id);
      toast.success("¡Caja abierta exitosamente!");
      
      // 2. Avisamos al componente padre (Ventas) que ya terminamos
      onAperturaCompletada();
    } catch (e) {
      toast.error("Error al abrir caja");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-stone-100 p-4">
      <div className="bg-white p-8 rounded-3xl shadow-xl max-w-md w-full text-center border border-stone-100">
        <div className="w-20 h-20 bg-emerald-100 rounded-full flex items-center justify-center mx-auto mb-6">
          <PlayCircle size={40} className="text-emerald-600"/>
        </div>
        
        <h1 className="text-2xl font-bold text-stone-800 mb-2">Iniciar Turno</h1>
        <p className="text-stone-500 mb-8">Ingresa el monto de efectivo inicial.</p>

        <div className="relative mb-6">
          <DollarSign className="absolute left-4 top-4 text-stone-400"/>
          <input 
            type="number" 
            autoFocus
            className="w-full pl-12 p-4 text-2xl font-bold border-2 border-stone-200 rounded-2xl outline-none focus:border-emerald-500 transition-all text-center"
            placeholder="0.00"
            value={monto}
            onChange={e => setMonto(e.target.value)}
          />
        </div>

        <button 
          onClick={handleApertura}
          disabled={loading}
          className="w-full bg-stone-900 text-white py-4 rounded-xl font-bold text-lg hover:bg-black transition-all shadow-lg flex justify-center items-center gap-2"
        >
          {loading ? <Loader2 className="animate-spin"/> : 'Abrir Caja'}
        </button>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useAuth } from '../hooks/useAuth';
import { registrarCierre, obtenerResumenCaja, CierreData } from '../services/cajaService';
import { toast } from 'sonner';
import { Calculator, Save, Lock, AlertTriangle, CheckCircle2, TrendingDown } from 'lucide-react';

interface ResumenCajaDB {
  total_cash: number;
  total_qr: number;
  total_card: number;
  last_closure: string;
}

export function CierreCaja() {
  const { orgId, user } = useAuth();
  const [loading, setLoading] = useState(false);
  
  // Estado del Sistema (Lo que dice la BD)
  const [sistema, setSistema] = useState({
    efectivo: 0,
    qr: 0,
    tarjeta: 0
  });

  // Estado del Cajero (Lo que cuenta manualmente)
  const [declarado, setDeclarado] = useState({
    efectivo: '', // Usamos string para permitir vacíos al escribir
    qr: '',
    tarjeta: '',
    gastos: '',
    notas: ''
  });

  useEffect(() => {
    if (orgId && user) cargarDatos();
  }, [orgId, user]);

const cargarDatos = async () => {
    try {
      const data = await obtenerResumenCaja(orgId!, user!.id);
      // Forzamos el tipo para que TS sepa qué viene
      const datosDB = data as unknown as {
          initial_cash: number;
          total_sales_cash: number;
          total_qr: number;
          total_card: number;
          total_system_cash: number;
      };
      
      if (datosDB) {
        setSistema({
          // El efectivo total debe ser: Lo que había al inicio + Ventas Efectivo
          efectivo: (datosDB.initial_cash || 0) + (datosDB.total_sales_cash || 0),
          qr: datosDB.total_qr || 0,
          tarjeta: datosDB.total_card || 0
        });
      }
    } catch (e) {
      toast.error("Error cargando datos de caja");
    }
  };

  const handleCierre = async () => {
    if (!declarado.efectivo) return toast.warning("Debes contar el efectivo");
    
    setLoading(true);
    try {
        const datosEnvio: CierreData = {
            system_cash: sistema.efectivo,
            system_qr: sistema.qr,
            system_card: sistema.tarjeta,
            declared_cash: Number(declarado.efectivo) || 0,
            declared_qr: Number(declarado.qr) || 0,
            declared_card: Number(declarado.tarjeta) || 0,
            cash_withdrawals: Number(declarado.gastos) || 0,
            notes: declarado.notas
        };

        await registrarCierre(datosEnvio, orgId!, user!.id);
        toast.success("Caja cerrada correctamente");
        // Reiniciar o redirigir
        setDeclarado({ efectivo: '', qr: '', tarjeta: '', gastos: '', notas: '' });
        cargarDatos();
    } catch (error: any) {
        toast.error("Error al cerrar caja");
    } finally {
        setLoading(false);
    }
  };

  // Cálculos en tiempo real
  const efectivoReal = Number(declarado.efectivo) || 0;
  const gastosCaja = Number(declarado.gastos) || 0;
  
  // Diferencia: (Lo que tengo + Lo que gasté) - (Lo que debería tener)
  const diferencia = (efectivoReal + gastosCaja) - sistema.efectivo;
  const cuadraPerfecto = Math.abs(diferencia) < 0.5; // Margen pequeño por redondeos

  return (
    <div className="p-6 bg-stone-50 min-h-screen">
