import React, { useState, useEffect } from 'react';
import { useAuth } from '../hooks/useAuth';
import { getTodosLosClientes, actualizarCliente, toggleEstadoCliente, ClienteForm } from '../services/clientesService';
import { toast } from 'sonner';
import { Users, Search, Edit2, CheckCircle, XCircle, Save } from 'lucide-react';
import { crearCliente } from '../services/ventasService'; // Reutilizamos crearCliente de ventasService o clientesService si lo tienes ahí

export function Clientes() {
  const { orgId } = useAuth();
  const [clientes, setClientes] = useState<any[]>([]);
  const [filtro, setFiltro] = useState('');
  const [editingId, setEditingId] = useState<string | null>(null);
  
  // Estado formulario edición/creación
  const [form, setForm] = useState<ClienteForm>({
    business_name: '', tax_id: '', email: '', phone: '', discount_rate: 0, notes: ''
  });

  useEffect(() => { if(orgId) cargar(); }, [orgId]);

  const cargar = () => getTodosLosClientes(orgId!).then(setClientes);

  const handleEdit = (c: any) => {
    setEditingId(c.id);
    setForm({
      business_name: c.business_name,
      tax_id: c.tax_id,
      email: c.email,
      phone: c.phone,
      discount_rate: c.discount_rate || 0,
      notes: c.notes
    });
  };

  const handleSave = async () => {
    if (!editingId) return; // Solo edición por ahora en esta vista rápida
    try {
      await actualizarCliente(editingId, form);
      toast.success("Cliente actualizado");
      setEditingId(null);
      cargar();
    } catch (e: any) { toast.error(e.message); }
  };

  const filtered = clientes.filter(c => c.business_name.toLowerCase().includes(filtro.toLowerCase()));

  return (
    <div className="p-6 bg-stone-50 h-[calc(100vh-64px)] overflow-hidden flex flex-col">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold text-stone-800 flex items-center gap-2"><Users className="text-blue-600"/> Directorio Clientes</h1>
        <div className="relative">
          <Search className="absolute left-3 top-2.5 text-stone-400" size={18}/>
          <input className="pl-10 p-2 border rounded-xl" placeholder="Buscar..." value={filtro} onChange={e=>setFiltro(e.target.value)}/>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-stone-200 overflow-hidden flex-1 overflow-y-auto">
        <table className="w-full text-left text-sm">
          <thead className="bg-stone-50 text-stone-500 font-bold uppercase">
            <tr><th className="p-4">Cliente</th><th className="p-4">Contacto</th><th className="p-4">NIT/CI</th><th className="p-4">Acciones</th></tr>
          </thead>
          <tbody className="divide-y divide-stone-100">
            {filtered.map(c => (
              <tr key={c.id} className="hover:bg-stone-50">
                <td className="p-4 font-bold text-stone-800">{c.business_name}</td>
                <td className="p-4 text-stone-500">{c.phone} <br/> <span className="text-xs">{c.email}</span></td>
                <td className="p-4 font-mono">{c.tax_id || '-'}</td>
                <td className="p-4 flex gap-2">
                  <button onClick={() => handleEdit(c)} className="p-2 hover:bg-blue-50 text-blue-600 rounded"><Edit2 size={16}/></button>
                  <button onClick={() => toggleEstadoCliente(c.id, !c.is_active).then(cargar)} className={`p-2 rounded ${c.is_active ? 'text-green-600 hover:bg-green-50' : 'text-red-400 hover:bg-red-50'}`}>
                    {c.is_active ? <CheckCircle size={16}/> : <XCircle size={16}/>}
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Modal Edición Rápida */}
      {editingId && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
          <div className="bg-white p-6 rounded-2xl w-full max-w-lg shadow-2xl">
            <h3 className="font-bold text-lg mb-4">Editar Cliente</h3>
            <div className="space-y-3">
              <input className="w-full p-2 border rounded" placeholder="Razón Social" value={form.business_name} onChange={e=>setForm({...form, business_name: e.target.value})}/>
              <div className="grid grid-cols-2 gap-3">
                <input className="w-full p-2 border rounded" placeholder="NIT/CI" value={form.tax_id || ''} onChange={e=>setForm({...form, tax_id: e.target.value})}/>
                <input className="w-full p-2 border rounded" placeholder="Teléfono" value={form.phone || ''} onChange={e=>setForm({...form, phone: e.target.value})}/>
              </div>
              <input className="w-full p-2 border rounded" placeholder="Email" value={form.email || ''} onChange={e=>setForm({...form, email: e.target.value})}/>
            </div>
            <div className="flex gap-3 mt-6">
              <button onClick={() => setEditingId(null)} className="flex-1 py-2 text-stone-500 font-bold">Cancelar</button>
              <button onClick={handleSave} className="flex-1 py-2 bg-stone-900 text-white rounded font-bold">Guardar</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useEffect, useState } from 'react';
import { useAuth } from '../hooks/useAuth';
import { getDashboardMetrics, DashboardData } from '../services/dashboardService';
import { StockAlerts } from '../components/StockAlerts';
import { TopProductsRanking } from '../components/TopProductsRanking';
import {
  TrendingUp, TrendingDown, DollarSign, ShoppingBag,
  Activity, Calendar, ClipboardList
} from 'lucide-react';
import { MetricCard } from '../components/ui';
import { useNavigate } from 'react-router-dom';

export function Dashboard() {
  const { user, profile, orgId } = useAuth();
  const [data, setData] = useState<DashboardData | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (orgId) {
      getDashboardMetrics(orgId)
        .then(setData)
        .finally(() => setLoading(false));
    }
  }, [orgId]);

  if (loading) return <div className="p-8 text-stone-400 animate-pulse">Cargando tablero de control...</div>;
  if (!data) return <div className="p-8">Sin datos disponibles.</div>;

  // Calculamos salud financiera
  const balance = data.ventasMes - data.gastosMes;
  const esPositivo = balance >= 0;

  return (
    <div className="p-6 max-w-7xl mx-auto space-y-8">

      {/* 1. BIENVENIDA Y RESUMEN RÁPIDO */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4">
        <div>
          <h1 className="text-3xl font-bold text-stone-800">
            Hola, {profile?.first_name || 'Admin'} 👋
          </h1>
          <p className="text-stone-500 mt-1">Aquí tienes el pulso de tu tostaduría hoy.</p>
        </div>
        <div className="bg-white px-4 py-2 rounded-full border border-stone-200 shadow-sm flex items-center gap-2 text-sm font-bold text-stone-600">
          <Calendar size={16} className="text-emerald-600" />
          {new Date().toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}
        </div>
      </div>

      {/* 2. TARJETAS KPI (FINANCIERAS) */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">

        {/* Ventas Hoy */}
        <div className="bg-stone-900 text-white p-6 rounded-2xl shadow-xl relative overflow-hidden group">
          <div className="absolute right-[-20px] top-[-20px] opacity-10 group-hover:opacity-20 transition-opacity">
            <DollarSign size={100} />
          </div>
          <p className="text-stone-400 text-xs font-bold uppercase tracking-wider mb-1">Ventas Hoy</p>
          <h3 className="text-3xl font-mono font-bold">Bs {data.ventasHoy.toLocaleString()}</h3>
          <div className="mt-4 flex items-center gap-2 text-xs text-emerald-400 bg-emerald-400/10 w-fit px-2 py-1 rounded-lg">
            <ShoppingBag size={12} /> {data.transaccionesHoy} transacciones
          </div>
        </div>

        {/* Balance Mes */}
        <div className="bg-white p-6 rounded-2xl border border-stone-200 shadow-sm relative overflow-hidden">
          <p className="text-stone-500 text-xs font-bold uppercase tracking-wider mb-1">Balance Mensual</p>
          <h3 className={`text-3xl font-mono font-bold ${esPositivo ? 'text-emerald-600' : 'text-red-500'}`}>
            {esPositivo ? '+' : ''}Bs {balance.toLocaleString()}
          </h3>
          <p className="text-xs text-stone-400 mt-2 flex items-center gap-1">
            {esPositivo ? <TrendingUp size={14} /> : <TrendingDown size={14} />}
            Ingresos vs Gastos
          </p>
        </div>

        {/* Ticket Promedio */}
        <div className="bg-white p-6 rounded-2xl border border-stone-200 shadow-sm">
          <p className="text-stone-500 text-xs font-bold uppercase tracking-wider mb-1">Ticket Promedio</p>
          <h3 className="text-3xl font-mono font-bold text-stone-800">Bs {data.ticketPromedio.toFixed(1)}</h3>
          <p className="text-xs text-stone-400 mt-2">Promedio por cliente hoy</p>
        </div>

        {/* Gastos Mes */}
        <div className="bg-white p-6 rounded-2xl border border-stone-200 shadow-sm">
          <p className="text-stone-500 text-xs font-bold uppercase tracking-wider mb-1">Gastos Ejecutados</p>
          <h3 className="text-3xl font-mono font-bold text-red-500">- Bs {data.gastosMes.toLocaleString()}</h3>
          <p className="text-xs text-stone-400 mt-2">Salidas registradas este mes</p>
        </div>
      </div>

      {/* 3. SECCIÓN MIXTA (META + ALERTAS) */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* Columna Izquierda: Meta Diaria Visual */}
        <div className="lg:col-span-2 bg-gradient-to-br from-emerald-50 to-white p-6 rounded-3xl border border-emerald-100 shadow-sm">
          <div className="flex justify-between items-center mb-6">
            <div>
              <h3 className="font-bold text-xl text-stone-800 flex items-center gap-2">
                <Activity className="text-emerald-600" /> Cobertura Diaria
              </h3>
              <p className="text-sm text-stone-500">Progreso para cubrir costos operativos del día.</p>
            </div>
            <span className="text-3xl font-bold text-emerald-700">{data.progresoMeta.toFixed(0)}%</span>
          </div>

          {/* Barra de Progreso Custom */}
          <div className="h-6 w-full bg-stone-200 rounded-full overflow-hidden shadow-inner relative">
            <div
              className="h-full bg-gradient-to-r from-emerald-500 to-emerald-400 transition-all duration-1000 ease-out flex items-center justify-end pr-2"
              style={{ width: `${data.progresoMeta}%` }}
            >
              {data.progresoMeta > 20 && <span className="text-[10px] font-bold text-white shadow-sm">META</span>}
            </div>
            {/* Marca del 100% */}
            <div className="absolute top-0 bottom-0 left-[100%] w-0.5 bg-stone-400 z-10 border-l border-dashed"></div>
          </div>

          <div className="mt-4 grid grid-cols-3 gap-4 text-center">
            <div className="p-3 bg-white rounded-xl shadow-sm border border-emerald-50">
              <p className="text-[10px] uppercase font-bold text-stone-400">Estado</p>
              <p className="font-bold text-emerald-700">{data.progresoMeta >= 100 ? 'Ganancia 🚀' : 'Cubriendo ⏳'}</p>
            </div>
            {/* Puedes agregar más métricas derivadas aquí */}
          </div>
        </div>

        {/* Columna Derecha: Alertas de Stock con Componente Mejorado */}
        <StockAlerts />

      </div>

      {/* 4. TOP PRODUCTOS MÁS VENDIDOS */}
      <TopProductsRanking days={30} limit={10} />

      {/* 5. ACCESOS RÁPIDOS ADMINISTRATIVOS */}
      {profile?.role === 'administrador' && (
        <div className="bg-white p-6 rounded-2xl border border-stone-200 shadow-sm">
          <h3 className="font-bold text-lg text-stone-800 mb-4">Accesos Rápidos</h3>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <button
              onClick={() => window.location.href = '/cierres-historico'}
              className="p-4 bg-gradient-to-br from-emerald-50 to-white rounded-xl border border-emerald-200 hover:border-emerald-400 transition-all hover:shadow-md group"
            >
              <div className="flex items-center gap-3">
                <div className="p-2 bg-emerald-100 rounded-lg group-hover:bg-emerald-200 transition-colors">
                  <ClipboardList size={24} className="text-emerald-700" />
                </div>
                <div className="text-left">
                  <p className="font-bold text-stone-800 group-hover:text-emerald-700 transition-colors">Cierres de Caja</p>
                  <p className="text-xs text-stone-500">Historial y reportes</p>
                </div>
              </div>
            </button>
          </div>
        </div>
      )}

    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useAuth } from '../hooks/useAuth';
import { getProductos, getBatchesDisponibles, registrarEmpaque } from '../services/empaqueService';
import { toast } from 'sonner';
import { Package, ArrowRight } from 'lucide-react';

export function Empaque() {
  const { orgId, user } = useAuth();
  const [productos, setProductos] = useState<any[]>([]);
  const [batches, setBatches] = useState<any[]>([]);
  
  // Selección
  const [selectedBatch, setSelectedBatch] = useState('');
  const [selectedProd, setSelectedProd] = useState('');
  const [cantidad, setCantidad] = useState('');

  useEffect(() => {
    if (orgId) {
      getProductos().then(setProductos); // Estos vienen del nuevo módulo Productos
      getBatchesDisponibles().then(setBatches);
    }
  }, [orgId]);

  const handleEmpaque = async () => {
    if (!selectedBatch || !selectedProd || !cantidad) return toast.warning("Datos incompletos");
    try {
      await registrarEmpaque({ 
        batch_id: selectedBatch, 
        product_id: selectedProd, 
        cantidad: cantidad 
      }, orgId!, user!.id);
      toast.success("Stock de producto actualizado");
      setCantidad('');
    } catch (e: any) { toast.error(e.message); }
  };

  // Solo mostramos productos tostados (Categoría Café o Grano) para empacar
  const productosCafé = productos.filter(p => p.is_roasted);

  return (
    <div className="max-w-3xl mx-auto p-6">
      <h1 className="text-2xl font-bold text-stone-800 mb-6 flex items-center gap-2"><Package className="text-amber-700"/> Sala de Empaque</h1>
      
      <div className="bg-white p-8 rounded-2xl shadow-xl border border-stone-200 space-y-6">
        
        <div>
           <label className="font-bold text-stone-500 text-sm">1. Origen (Lote Tostado)</label>
           <select className="w-full p-3 border rounded-xl mt-1 bg-stone-50" value={selectedBatch} onChange={e=>setSelectedBatch(e.target.value)}>
             <option value="">-- Seleccionar Tueste --</option>
             {batches.map(b => (
               <option key={b.id} value={b.id}>
                 {new Date(b.fecha).toLocaleDateString()} - {b.origen_nombre} ({b.peso_inicial}kg)
               </option>
             ))}
           </select>
        </div>

        <div>
           <label className="font-bold text-stone-500 text-sm">2. Producto Final (SKU)</label>
           <select className="w-full p-3 border rounded-xl mt-1 bg-stone-50" value={selectedProd} onChange={e=>setSelectedProd(e.target.value)}>
             <option value="">-- Seleccionar Bolsa --</option>
             {productosCafé.map(p => (
               <option key={p.id} value={p.id}>{p.name} ({p.sku})</option>
             ))}
           </select>
        </div>

        <div>
           <label className="font-bold text-stone-500 text-sm">3. Cantidad Bolsas</label>
           <input type="number" className="w-full p-3 border rounded-xl mt-1 font-bold text-xl" value={cantidad} onChange={e=>setCantidad(e.target.value)} placeholder="0"/>
        </div>

        <button onClick={handleEmpaque} className="w-full bg-stone-900 text-white py-4 rounded-xl font-bold text-lg hover:bg-black transition-all flex justify-center items-center gap-2">
           <Package/> Registrar Empaque
        </button>

      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { 
  DollarSign, Calendar, Plus, Trash2, TrendingDown, CreditCard, 
  LayoutList, Settings, Wallet, X
} from 'lucide-react';
import { useAuth } from '../hooks/useAuth';
import { toast } from 'sonner';
import { 
  getGastosFijos, crearGastoFijo, registrarPago, getHistorialPagos, eliminarGastoFijo,
  GastoFijoForm, RegistroPagoForm 
} from '../services/gastosService';

export function Gastos() {
  const { orgId } = useAuth();
  const [activeTab, setActiveTab] = useState<'libro' | 'config'>('libro');
  const [loading, setLoading] = useState(false);
  
  // Datos
  const [fijos, setFijos] = useState<any[]>([]);
  const [historial, setHistorial] = useState<any[]>([]);

  // Formularios
  const [nuevoFijo, setNuevoFijo] = useState<GastoFijoForm>({ name: '', amount: '', category: 'otros', frequency: 'mensual' });
  const [nuevoPago, setNuevoPago] = useState<RegistroPagoForm>({ description: '', amount_paid: '', payment_date: new Date().toISOString().split('T')[0], payment_method: 'transferencia', expense_id: '' });

  useEffect(() => {
    if (orgId) cargarDatos();
  }, [orgId, activeTab]);

  const cargarDatos = async () => {
    try {
      const [f, h] = await Promise.all([getGastosFijos(orgId!), getHistorialPagos(orgId!)]);
      setFijos(f);
      setHistorial(h);
    } catch (e) { console.error(e); }
  };

  const handleCrearFijo = async () => {
    if (!nuevoFijo.name || !nuevoFijo.amount) return toast.warning("Datos incompletos");
    setLoading(true);
    try {
      await crearGastoFijo(nuevoFijo, orgId!);
      toast.success("Gasto recurrente guardado");
      setNuevoFijo({ name: '', amount: '', category: 'otros', frequency: 'mensual' });
      cargarDatos();
    } catch (e: any) { toast.error(e.message); }
    finally { setLoading(false); }
  };

  const handleRegistrarPago = async () => {
    if (!nuevoPago.amount_paid || !nuevoPago.description) return toast.warning("Indica monto y concepto");
    setLoading(true);
    try {
      await registrarPago(nuevoPago, orgId!);
      toast.success("Pago registrado");
      setNuevoPago({ ...nuevoPago, description: '', amount_paid: '', expense_id: '' });
      cargarDatos();
    } catch (e: any) { toast.error(e.message); }
    finally { setLoading(false); }
  };

  const prellenarPago = (gastoFijo: any) => {
    setNuevoPago({
      ...nuevoPago,
      expense_id: gastoFijo.id,
      description: `Pago: ${gastoFijo.name}`,
      amount_paid: gastoFijo.amount
    });
    setActiveTab('libro');
    toast.info(`Confirma el pago de: ${gastoFijo.name}`);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-64px)] bg-stone-50 overflow-hidden">
      
      {/* HEADER TABS RESPONSIVO */}
      <div className="bg-white border-b border-stone-200 px-4 py-3 flex flex-col md:flex-row md:items-center justify-between shadow-sm z-10 gap-3">
        <div className="flex gap-2 w-full md:w-auto">
          <button onClick={()=>setActiveTab('libro')} className={`flex-1 md:flex-none justify-center px-4 py-2.5 rounded-lg text-sm font-bold flex items-center gap-2 transition-all ${activeTab==='libro' ? 'bg-stone-900 text-white shadow-md' : 'bg-stone-100 text-stone-500'}`}>
            <LayoutList size={18}/> Libro Diario
          </button>
          <button onClick={()=>setActiveTab('config')} className={`flex-1 md:flex-none justify-center px-4 py-2.5 rounded-lg text-sm font-bold flex items-center gap-2 transition-all ${activeTab==='config' ? 'bg-stone-900 text-white shadow-md' : 'bg-stone-100 text-stone-500'}`}>
            <Settings size={18}/> Configuración
          </button>
        </div>
        
        {/* Total Gastos (Visible en móvil como tarjeta compacta) */}
        <div className="flex items-center justify-between md:justify-end bg-red-50 px-7 py-2 rounded-lg border border-red-100 w-full md:w-auto">
          <span className="text-xs uppercase text-red-400 font-bold flex items-left gap-1"><Wallet size={14}/> Salidas Mes : </span>
          <span className="text-lg font-mono font-bold text-red-600">Bs {historial.reduce((sum, h) => sum + h.monto, 0).toLocaleString()}</span>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 md:p-6 scrollbar-hide">
        
        {/* --- PESTAÑA 1: LIBRO DIARIO (REGISTRO) --- */}
        {activeTab === 'libro' && (
          <div className="max-w-5xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-6">
            
            {/* Formulario Registro */}
            <div className="bg-white p-5 rounded-2xl shadow-sm border border-stone-100 h-fit order-1">
              <h3 className="font-bold text-stone-800 mb-4 flex items-center gap-2 text-sm uppercase tracking-wider">
                <CreditCard size={16} className="text-red-500"/> Nueva Salida
              </h3>
              
              <div className="space-y-4">
                {nuevoPago.expense_id && (
                  <div className="bg-blue-50 text-blue-800 p-3 rounded-xl text-sm flex justify-between items-center animate-in fade-in zoom-in">
                    <span className="truncate mr-2">Pagar: <b>{nuevoPago.description.replace('Pago: ', '')}</b></span>
                    <button onClick={()=>setNuevoPago({...nuevoPago, expense_id: '', description: '', amount_paid: ''})} className="bg-blue-100 p-1 rounded-full hover:bg-blue-200"><X size={14}/></button>
                  </div>
                )}

                <div>
                  <label className="text-xs font-bold text-stone-400 uppercase">Concepto</label>
                  <input className="w-full p-3 border rounded-xl mt-1 focus:ring-2 focus:ring-emerald-500 outline-none" placeholder="Ej: Compra de Leche" value={nuevoPago.description} onChange={e=>setNuevoPago({...nuevoPago, description: e.target.value})}/>
                </div>
                
                <div className="grid grid-cols-2 gap-3">
                  <div>
                    <label className="text-xs font-bold text-stone-400 uppercase">Monto</label>
                    <div className="relative mt-1">
                      <span className="absolute left-3 top-3 text-stone-400 font-bold text-xs">Bs</span>
                      <input type="number" className="w-full pl-8 p-3 border rounded-xl font-bold text-red-600 outline-none" placeholder="0.00" value={nuevoPago.amount_paid} onChange={e=>setNuevoPago({...nuevoPago, amount_paid: e.target.value})}/>
                    </div>
                  </div>
                  <div>
                    <label className="text-xs font-bold text-stone-400 uppercase">Fecha</label>
                    <input type="date" className="w-full p-3 border rounded-xl mt-1 text-sm bg-white" value={nuevoPago.payment_date} onChange={e=>setNuevoPago({...nuevoPago, payment_date: e.target.value})}/>
                  </div>
                </div>

                <button onClick={handleRegistrarPago} disabled={loading} className="w-full bg-red-600 hover:bg-red-700 active:scale-95 text-white py-4 rounded-xl font-bold shadow-lg transition-all flex justify-center gap-2 mt-2">
                  {loading ? '...' : <><TrendingDown size={20}/> Registrar Gasto</>}
                </button>
              </div>
            </div>

            {/* Historial (Responsive: Cards en móvil, Tabla en PC) */}
            <div className="lg:col-span-2 order-2">
              <h3 className="font-bold text-stone-500 text-xs uppercase mb-3 ml-1">Últimos Movimientos</h3>
              
              {/* Vista Móvil (Cards) */}
              <div className="md:hidden space-y-3">
                {historial.map(h => (
                  <div key={h.id} className="bg-white p-4 rounded-xl border border-stone-100 shadow-sm flex justify-between items-center">
                    <div>
                      <p className="font-bold text-stone-800 text-sm">{h.descripcion}</p>
                      <p className="text-xs text-stone-400 mt-0.5">{new Date(h.fecha).toLocaleDateString()} • {h.categoria}</p>
                    </div>
                    <span className="font-bold text-red-600 font-mono text-lg">- {h.monto}</span>
                  </div>
                ))}
              </div>

              {/* Vista Desktop (Tabla) */}
              <div className="hidden md:block bg-white rounded-2xl shadow-sm border border-stone-200 overflow-hidden">
                <table className="w-full text-left text-sm">
                  <thead className="bg-stone-50 text-stone-400 font-bold border-b border-stone-100">
                    <tr><th className="p-4">Fecha</th><th className="p-4">Concepto</th><th className="p-4">Categoría</th><th className="p-4 text-right">Monto</th></tr>
                  </thead>
                  <tbody className="divide-y divide-stone-50">
                    {historial.map(h => (
                      <tr key={h.id} className="hover:bg-stone-50">
                        <td className="p-4 text-stone-500 font-mono text-xs">{h.fecha}</td>
                        <td className="p-4 font-medium text-stone-800">{h.descripcion}</td>
                        <td className="p-4"><span className="px-2 py-1 bg-stone-100 rounded-full text-[10px] uppercase font-bold text-stone-500">{h.categoria}</span></td>
                        <td className="p-4 text-right font-bold text-red-600">- {h.monto}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
              
              {historial.length === 0 && <div className="text-center p-8 text-stone-400 italic bg-white rounded-xl border border-dashed">No hay gastos registrados.</div>}
            </div>
          </div>
        )}

        {/* --- PESTAÑA 2: CONFIGURACIÓN FIJOS --- */}
        {activeTab === 'config' && (
          <div className="max-w-4xl mx-auto space-y-6">
            
            {/* Formulario Crear (Stack en móvil, Row en PC) */}
            <div className="bg-white p-5 rounded-2xl shadow-sm border border-stone-200 flex flex-col md:flex-row gap-4 items-end">
              <div className="flex-1 w-full space-y-1">
                <label className="text-xs font-bold text-stone-400 uppercase">Nombre del Gasto</label>
                <input className="w-full p-3 border rounded-xl bg-stone-50 focus:bg-white transition-colors outline-none" placeholder="Ej: Alquiler Local" value={nuevoFijo.name} onChange={e=>setNuevoFijo({...nuevoFijo, name: e.target.value})}/>
              </div>
              <div className="w-full md:w-32 space-y-1">
                <label className="text-xs font-bold text-stone-400 uppercase">Monto Fijo</label>
                <input type="number" className="w-full p-3 border rounded-xl" placeholder="0" value={nuevoFijo.amount} onChange={e=>setNuevoFijo({...nuevoFijo, amount: e.target.value})}/>
              </div>
              <div className="w-full md:w-40 space-y-1">
                <label className="text-xs font-bold text-stone-400 uppercase">Categoría</label>
                <select className="w-full p-3 border rounded-xl bg-white" value={nuevoFijo.category} onChange={e=>setNuevoFijo({...nuevoFijo, category: e.target.value})}>
                  <option value="alquiler">Alquiler</option>
                  <option value="nomina">Nómina</option>
                  <option value="servicios">Servicios</option>
                  <option value="insumos_cafeteria">Insumos</option>
                  <option value="otros">Otros</option>
                </select>
              </div>
              <button onClick={handleCrearFijo} className="w-full md:w-auto bg-stone-900 text-white p-3 rounded-xl hover:bg-black transition-colors flex justify-center items-center">
                <Plus size={24}/> <span className="md:hidden ml-2 font-bold">Agregar Gasto</span>
              </button>
            </div>

            {/* Lista Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {fijos.map(f => (
                <div key={f.id} className="bg-white p-5 rounded-xl border border-stone-200 shadow-sm flex justify-between items-center group hover:border-emerald-400 transition-colors relative overflow-hidden">
                  <div className="absolute left-0 top-0 bottom-0 w-1 bg-stone-200 group-hover:bg-emerald-400 transition-colors"></div>
                  <div>
                    <h4 className="font-bold text-stone-800 text-lg">{f.name}</h4>
                    <p className="text-xs text-stone-500 uppercase tracking-wide mt-1 flex items-center gap-2">
                      <Calendar size={12}/> {f.frequency} • {f.category}
                    </p>
                  </div>
                  <div className="text-right">
                    <p className="font-mono font-bold text-stone-700 text-xl">Bs {f.amount}</p>
                    <div className="flex gap-3 justify-end mt-2">
                      <button onClick={() => prellenarPago(f)} className="text-xs bg-emerald-100 text-emerald-800 px-3 py-1.5 rounded-lg hover:bg-emerald-200 font-bold transition-colors">
                        Pagar Ahora
                      </button>
                      <button onClick={() => { if(confirm('¿Borrar?')) eliminarGastoFijo(f.id).then(cargarDatos); }} className="text-stone-300 hover:text-red-500 transition-colors">
                        <Trash2 size={18}/>
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useAuth } from '../hooks/useAuth';
import { getCierresHistorico, getDetalleCierre, CierreHistorico, DetalleCierre } from '../services/cajaService';
import { toast } from 'sonner';
import {
    FileText, Search, Calendar, User, X, TrendingUp,
    AlertCircle, CheckCircle, Banknote, QrCode, CreditCard,
    Clock, DollarSign, Package, ChevronDown
} from 'lucide-react';

export function HistorialCierres() {
    const { orgId } = useAuth();
    const [cierres, setCierres] = useState<CierreHistorico[]>([]);
    const [loading, setLoading] = useState(false);
    const [showDetalle, setShowDetalle] = useState(false);
    const [cierreSeleccionado, setCierreSeleccionado] = useState<DetalleCierre | null>(null);
    const [loadingDetalle, setLoadingDetalle] = useState(false);

    // Filtros
    const [fechaDesde, setFechaDesde] = useState('');
    const [fechaHasta, setFechaHasta] = useState('');
    const [cajeroFiltro, setCajeroFiltro] = useState('');

    // Lista de cajeros únicos
    const cajerosUnicos = Array.from(new Set(cierres.map(c => c.user_name)));

    useEffect(() => {
        if (orgId) cargarCierres();
    }, [orgId]);

    const cargarCierres = async () => {
        setLoading(true);
        try {
            const filtros: any = {};
            if (fechaDesde) filtros.fechaDesde = new Date(fechaDesde).toISOString();
            if (fechaHasta) {
                const fecha = new Date(fechaHasta);
                fecha.setHours(23, 59, 59);
                filtros.fechaHasta = fecha.toISOString();
            }
            if (cajeroFiltro) {
                // Buscar el user_id del cajero seleccionado
                const cajero = cierres.find(c => c.user_name === cajeroFiltro);
                if (cajero) filtros.userId = cajero.user_id;
            }

            const data = await getCierresHistorico(orgId!, filtros);
            setCierres(data);
        } catch (e: any) {
            toast.error('Error al cargar cierres', { description: e.message });
        } finally {
            setLoading(false);
        }
    };

    const verDetalle = async (cierreId: string) => {
        setLoadingDetalle(true);
        setShowDetalle(true);
        try {
            const detalle = await getDetalleCierre(cierreId);
            setCierreSeleccionado(detalle);
        } catch (e: any) {
            toast.error('Error al cargar detalle', { description: e.message });
            setShowDetalle(false);
        } finally {
            setLoadingDetalle(false);
        }
    };

    const formatearFecha = (fecha: string) => {
        const date = new Date(fecha);
        return date.toLocaleDateString('es-BO', {
            year: 'numeric',
            month: 'short',
            day: 'numeric',
            hour: '2-digit',
            minute: '2-digit'
        });
    };

    return (
        <div className="p-6 bg-stone-50 min-h-screen">
            {/* Header */}
            <div className="mb-6">
                <h1 className="text-3xl font-bold text-stone-800 flex items-center gap-2">
                    <FileText className="text-emerald-600" />
                    Historial de Cierres de Caja
                </h1>
                <p className="text-stone-500 mt-1">
                    Consulta y revisa los movimientos de caja de cada cajero
                </p>
            </div>

            {/* Filtros */}
            <div className="bg-white p-4 rounded-xl shadow-sm border border-stone-200 mb-6">
                <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                    <div>
                        <label className="text-xs font-bold text-stone-600 mb-2 flex items-center gap-1">
                            <Calendar size={12} />
                            Desde
                        </label>
                        <input
                            type="date"
                            className="w-full p-2 border border-stone-200 rounded-lg text-sm focus:border-emerald-500 outline-none"
                            value={fechaDesde}
                            onChange={e => setFechaDesde(e.target.value)}
                        />
                    </div>

                    <div>
                        <label className="text-xs font-bold text-stone-600 mb-2 flex items-center gap-1">
                            <Calendar size={12} />
                            Hasta
                        </label>
                        <input
                            type="date"
                            className="w-full p-2 border border-stone-200 rounded-lg text-sm focus:border-emerald-500 outline-none"
                            value={fechaHasta}
                            onChange={e => setFechaHasta(e.target.value)}
                        />
                    </div>

                    <div>
                        <label className="text-xs font-bold text-stone-600 mb-2 flex items-center gap-1">
                            <User size={12} />
                            Cajero
                        </label>
                        <div className="relative">
                            <select
                                className="w-full p-2 border border-stone-200 rounded-lg text-sm focus:border-emerald-500 outline-none appearance-none pr-8 bg-white"
                                value={cajeroFiltro}
                                onChange={e => setCajeroFiltro(e.target.value)}
                            >
                                <option value="">Todos</option>
                                {cajerosUnicos.map(cajero => (
                                    <option key={cajero} value={cajero}>{cajero}</option>
                                ))}
                            </select>
                            <ChevronDown size={16} className="absolute right-2 top-3 text-stone-400 pointer-events-none" />
                        </div>
                    </div>

                    <div className="flex items-end">
                        <button
                            onClick={cargarCierres}
                            disabled={loading}
                            className="w-full bg-stone-900 text-white py-2 rounded-lg font-bold text-sm hover:bg-black transition-colors disabled:opacity-50 flex items-center justify-center gap-2"
                        >
                            {loading ? (
                                <>
                                    <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white"></div>
                                    Buscando...
                                </>
                            ) : (
                                <>
                                    <Search size={16} />
                                    Buscar
                                </>
                            )}
                        </button>
                    </div>
                </div>
            </div>

            {/* Tabla de Cierres */}
            <div className="bg-white rounded-xl shadow-sm border border-stone-200 overflow-hidden">
                {cierres.length === 0 ? (
                    <div className="flex flex-col items-center justify-center py-16 text-center">
                        <Package className="w-16 h-16 text-stone-300 mb-4" />
                        <p className="text-stone-500 font-bold text-lg">No hay cierres registrados</p>
                        <p className="text-sm text-stone-400 mt-2">
                            {fechaDesde || fechaHasta || cajeroFiltro
                                ? 'No se encontraron cierres con los filtros seleccionados'
                                : 'Los cierres de caja aparecerán aquí una vez que se registren'}
                        </p>
                    </div>
                ) : (
                    <div className="overflow-x-auto">
                        <table className="w-full">
                            <thead className="bg-stone-50 border-b border-stone-200">
                                <tr>
                                    <th className="px-4 py-3 text-left text-xs font-bold text-stone-600 uppercase">Fecha/Hora</th>
                                    <th className="px-4 py-3 text-left text-xs font-bold text-stone-600 uppercase">Cajero</th>
                                    <th className="px-4 py-3 text-right text-xs font-bold text-stone-600 uppercase">Apertura</th>
                                    <th className="px-4 py-3 text-right text-xs font-bold text-stone-600 uppercase">Ventas</th>
                                    <th className="px-4 py-3 text-right text-xs font-bold text-stone-600 uppercase">Efectivo Esp.</th>
                                    <th className="px-4 py-3 text-right text-xs font-bold text-stone-600 uppercase">Diferencia</th>
                                    <th className="px-4 py-3 text-center text-xs font-bold text-stone-600 uppercase">Acciones</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-stone-100">
                                {cierres.map((cierre) => {
                                    const totalVentas = cierre.system_cash - cierre.initial_cash;
                                    const cuadrado = Math.abs(cierre.difference) < 0.5;

                                    return (
                                        <tr key={cierre.id} className="hover:bg-stone-50 transition-colors">
                                            <td className="px-4 py-3 text-sm text-stone-700">
                                                <div className="flex items-center gap-2">
                                                    <Clock size={14} className="text-stone-400" />
                                                    {formatearFecha(cierre.closed_at)}
                                                </div>
                                            </td>
                                            <td className="px-4 py-3 text-sm font-medium text-stone-800">
                                                {cierre.user_name}
                                                <span className="text-xs text-stone-400 ml-2">({cierre.sales_count} ventas)</span>
                                            </td>
                                            <td className="px-4 py-3 text-sm text-right font-mono text-stone-700">
                                                Bs {cierre.initial_cash.toFixed(2)}
                                            </td>
                                            <td className="px-4 py-3 text-sm text-right font-mono text-emerald-600 font-bold">
                                                Bs {totalVentas.toFixed(2)}
                                            </td>
                                            <td className="px-4 py-3 text-sm text-right font-mono text-stone-700">
                                                Bs {cierre.system_cash.toFixed(2)}
                                            </td>
                                            <td className="px-4 py-3 text-sm text-right">
                                                <span className={`inline-flex items-center gap-1 px-2 py-1 rounded-full text-xs font-bold ${cuadrado
                                                    ? 'bg-emerald-100 text-emerald-700'
                                                    : 'bg-red-100 text-red-700'
                                                    }`}>
                                                    {cuadrado ? <CheckCircle size={12} /> : <AlertCircle size={12} />}
                                                    {cierre.difference > 0 ? '+' : ''}{cierre.difference.toFixed(2)} Bs
                                                </span>
                                            </td>
                                            <td className="px-4 py-3 text-center">
                                                <button
                                                    onClick={() => verDetalle(cierre.id)}
                                                    className="text-blue-600 hover:text-blue-800 font-bold text-xs hover:underline"
                                                >
                                                    Ver Detalle
                                                </button>
                                            </td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>

            {/* Modal de Detalle */}
            {showDetalle && (
                <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center p-4 z-50">
                    <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto">
                        {/* Header del Modal */}
                        <div className="sticky top-0 bg-white border-b border-stone-200 p-6 flex justify-between items-center">
                            <div>
                                <h2 className="text-2xl font-bold text-stone-800">Detalle de Cierre</h2>
                                {cierreSeleccionado && (
                                    <p className="text-sm text-stone-500 mt-1">
                                        {cierreSeleccionado.cierre.user_name} - {formatearFecha(cierreSeleccionado.cierre.closed_at)}
                                    </p>
                                )}
                            </div>
                            <button
                                onClick={() => setShowDetalle(false)}
                                className="p-2 hover:bg-stone-100 rounded-lg transition-colors"
                            >
                                <X size={20} className="text-stone-400" />
                            </button>
                        </div>

                        {loadingDetalle ? (
                            <div className="flex items-center justify-center py-20">
                                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-emerald-600"></div>
                            </div>
                        ) : cierreSeleccionado && (
                            <div className="p-6 space-y-6">
                                {/* Sección Apertura */}
                                <div className="bg-blue-50 p-4 rounded-xl border border-blue-100">
                                    <h3 className="font-bold text-blue-800 mb-3 flex items-center gap-2">
                                        <TrendingUp size={18} />
                                        Apertura de Caja
                                    </h3>
                                    <div className="grid grid-cols-2 gap-4">
                                        <div>
                                            <p className="text-xs text-blue-600 mb-1">Monto Inicial</p>
                                            <p className="text-2xl font-bold font-mono text-blue-900">
                                                Bs {cierreSeleccionado.cierre.initial_cash.toFixed(2)}
                                            </p>
                                        </div>
                                        <div>
                                            <p className="text-xs text-blue-600 mb-1">Hora de Apertura</p>
                                            <p className="text-sm font-medium text-blue-900">
                                                {formatearFecha(cierreSeleccionado.cierre.opened_at)}
                                            </p>
                                        </div>
                                    </div>
                                </div>

                                {/* Sección Ventas */}
                                <div className="bg-emerald-50 p-4 rounded-xl border border-emerald-100">
                                    <h3 className="font-bold text-emerald-800 mb-3 flex items-center gap-2">
                                        <DollarSign size={18} />
                                        Ventas del Turno
                                    </h3>
                                    <div className="grid grid-cols-3 gap-3">
                                        <div className="bg-white p-3 rounded-lg border border-emerald-200">
                                            <div className="flex items-center gap-2 mb-2">
                                                <Banknote size={16} className="text-emerald-600" />
                                                <p className="text-xs text-emerald-700 font-bold">Efectivo</p>
                                            </div>
                                            <p className="text-lg font-bold font-mono text-emerald-900">
                                                Bs {cierreSeleccionado.ventas.efectivo.total.toFixed(2)}
                                            </p>
                                            <p className="text-xs text-emerald-600">
                                                {cierreSeleccionado.ventas.efectivo.count} transacciones
                                            </p>
                                        </div>

                                        <div className="bg-white p-3 rounded-lg border border-emerald-200">
                                            <div className="flex items-center gap-2 mb-2">
                                                <QrCode size={16} className="text-emerald-600" />
                                                <p className="text-xs text-emerald-700 font-bold">QR</p>
                                            </div>
                                            <p className="text-lg font-bold font-mono text-emerald-900">
                                                Bs {cierreSeleccionado.ventas.qr.total.toFixed(2)}
                                            </p>
                                            <p className="text-xs text-emerald-600">
                                                {cierreSeleccionado.ventas.qr.count} transacciones
                                            </p>
                                        </div>

                                        <div className="bg-white p-3 rounded-lg border border-emerald-200">
                                            <div className="flex items-center gap-2 mb-2">
                                                <CreditCard size={16} className="text-emerald-600" />
                                                <p className="text-xs text-emerald-700 font-bold">Tarjeta</p>
                                            </div>
                                            <p className="text-lg font-bold font-mono text-emerald-900">
                                                Bs {cierreSeleccionado.ventas.tarjeta.total.toFixed(2)}
                                            </p>
                                            <p className="text-xs text-emerald-600">
                                                {cierreSeleccionado.ventas.tarjeta.count} transacciones
                                            </p>
                                        </div>
                                    </div>

                                    <div className="mt-3 pt-3 border-t border-emerald-200">
                                        <div className="flex justify-between items-center">
                                            <p className="text-sm font-bold text-emerald-800">Total Ventas</p>
                                            <p className="text-xl font-bold font-mono text-emerald-900">
                                                Bs {(
                                                    cierreSeleccionado.ventas.efectivo.total +
                                                    cierreSeleccionado.ventas.qr.total +
                                                    cierreSeleccionado.ventas.tarjeta.total
                                                ).toFixed(2)}
                                            </p>
                                        </div>
                                    </div>
                                </div>

                                {/* Sección Cierre */}
                                <div className="bg-stone-50 p-4 rounded-xl border border-stone-200">
                                    <h3 className="font-bold text-stone-800 mb-3 flex items-center gap-2">
                                        <FileText size={18} />
                                        Cierre de Caja
                                    </h3>

                                    <div className="space-y-3">
                                        <div className="flex justify-between items-center">
                                            <p className="text-sm text-stone-600">Efectivo Esperado</p>
                                            <p className="font-mono font-bold text-stone-800">
                                                Bs {cierreSeleccionado.cierre.system_cash.toFixed(2)}
                                            </p>
                                        </div>

                                        <div className="flex justify-between items-center">
                                            <p className="text-sm text-stone-600">Efectivo Declarado</p>
                                            <p className="font-mono font-bold text-stone-800">
                                                Bs {cierreSeleccionado.cierre.declared_cash.toFixed(2)}
                                            </p>
                                        </div>

                                        {cierreSeleccionado.cierre.cash_withdrawals > 0 && (
                                            <div className="flex justify-between items-center">
                                                <p className="text-sm text-stone-600">Gastos/Retiros</p>
                                                <p className="font-mono font-bold text-red-600">
                                                    - Bs {cierreSeleccionado.cierre.cash_withdrawals.toFixed(2)}
                                                </p>
                                            </div>
                                        )}

                                        <div className="pt-3 border-t border-stone-200">
                                            <div className={`flex justify-between items-center p-3 rounded-lg ${Math.abs(cierreSeleccionado.cierre.difference) < 0.5
                                                ? 'bg-emerald-100'
                                                : 'bg-red-100'
                                                }`}>
                                                <p className="font-bold text-sm flex items-center gap-2">
                                                    {Math.abs(cierreSeleccionado.cierre.difference) < 0.5 ? (
                                                        <CheckCircle size={18} className="text-emerald-700" />
                                                    ) : (
                                                        <AlertCircle size={18} className="text-red-700" />
                                                    )}
                                                    <span className={Math.abs(cierreSeleccionado.cierre.difference) < 0.5 ? 'text-emerald-800' : 'text-red-800'}>
                                                        Diferencial
                                                    </span>
                                                </p>
                                                <p className={`text-xl font-bold font-mono ${Math.abs(cierreSeleccionado.cierre.difference) < 0.5
                                                    ? 'text-emerald-700'
                                                    : 'text-red-700'
                                                    }`}>
                                                    {cierreSeleccionado.cierre.difference > 0 ? '+' : ''}
                                                    {cierreSeleccionado.cierre.difference.toFixed(2)} Bs
                                                </p>
                                            </div>
                                        </div>

                                        {cierreSeleccionado.cierre.notes && (
                                            <div className="pt-3 border-t border-stone-200">
                                                <p className="text-xs font-bold text-stone-600 mb-2">Notas del Cajero</p>
                                                <p className="text-sm text-stone-700 bg-white p-3 rounded-lg border border-stone-200">
                                                    {cierreSeleccionado.cierre.notes}
                                                </p>
                                            </div>
                                        )}

                                        <div className="text-xs text-stone-500 text-right pt-2">
                                            Cerrado: {formatearFecha(cierreSeleccionado.cierre.closed_at)}
                                        </div>
                                    </div>
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            )}
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { 
  Package, Plus, Search, Edit2, AlertTriangle, 
  Trash2, X, Save, Calculator, Calendar, History, ArrowRight 
} from 'lucide-react';
import { useAuth } from '../hooks/useAuth';
import { toast } from 'sonner';
import { getInsumos, crearInsumo, actualizarInsumo, eliminarInsumo, registrarHistorialCompra } from '../services/insumosService';
import { Database } from '../types/supabase';

type Insumo = Database['public']['Tables']['supplies_inventory']['Row'];

export function Insumos() {
  const { orgId } = useAuth();
  const [insumos, setInsumos] = useState<Insumo[]>([]);
  const [loading, setLoading] = useState(true);
  const [filtro, setFiltro] = useState('');

  // Control del Modal
  const [showModal, setShowModal] = useState(false);
  const [modoEdicion, setModoEdicion] = useState(false);

  // --- ESTADO DEL FORMULARIO ---
  const [form, setForm] = useState({
    id: '',
    name: '',
    unit_measure: 'ml',
    low_stock_threshold: 1000,
    
    // DATOS DE COMPRA (Calculadora)
    presentacion_nombre: 'Unidad', 
    contenido_neto: 1000,       
    costo_presentacion: 0,      
    cantidad_comprada: 1,       
    fecha_compra: new Date().toISOString().split('T')[0], // Default: Hoy

    // RESULTADOS
    costo_unitario_calculado: 0,
    stock_calculado: 0
  });

  const [stockActualBD, setStockActualBD] = useState(0);

  useEffect(() => {
    if (orgId) cargarDatos();
  }, [orgId]);

  // --- CALCULADORA AUTOMÁTICA ---
  useEffect(() => {
    const costo = Number(form.costo_presentacion) || 0;
    const contenido = Number(form.contenido_neto) || 1; 
    const cantidad = Number(form.cantidad_comprada) || 0;

    const costoPorUnidad = contenido > 0 ? (costo / contenido) : 0;
    const stockCompra = contenido * cantidad;

    setForm(prev => ({
      ...prev,
      costo_unitario_calculado: costoPorUnidad,
      stock_calculado: stockCompra
    }));
  }, [form.costo_presentacion, form.contenido_neto, form.cantidad_comprada]);

  const cargarDatos = async () => {
    setLoading(true);
    try {
      const data = await getInsumos(orgId!);
      setInsumos(data);
    } catch (e) { console.error(e); } 
    finally { setLoading(false); }
  };

  const abrirModalCrear = () => {
    setModoEdicion(false);
    setStockActualBD(0);
    setForm({
      id: '', name: '', unit_measure: 'ml', low_stock_threshold: 500,
      presentacion_nombre: 'Paquete', contenido_neto: 1000, costo_presentacion: 0, cantidad_comprada: 1,
      fecha_compra: new Date().toISOString().split('T')[0],
      costo_unitario_calculado: 0, stock_calculado: 0
    });
    setShowModal(true);
  };

  const abrirModalEditar = (item: Insumo) => {
    setModoEdicion(true);
    setStockActualBD(item.current_stock ?? 0);
    
    setForm({
      id: item.id,
      name: item.name,
      unit_measure: item.unit_measure,
      low_stock_threshold: item.low_stock_threshold ?? 0,
      
      presentacion_nombre: 'Unidad', // Reseteamos para nueva compra
      contenido_neto: 1, 
      costo_presentacion: item.unit_cost ?? 0, // Sugerimos costo anterior
      cantidad_comprada: 0, // 0 para no sumar accidentalmente
      fecha_compra: new Date().toISOString().split('T')[0],

      costo_unitario_calculado: item.unit_cost ?? 0,
      stock_calculado: 0
    });
    setShowModal(true);
  };

  const handleGuardar = async () => {
    if (!form.name) return toast.warning("El nombre es obligatorio");
    setLoading(true);

    try {
      const costoTotalCompra = form.costo_presentacion * form.cantidad_comprada;
      const descripcionHistorial = `Compra: ${form.cantidad_comprada} ${form.presentacion_nombre}(s) de ${form.name}`;

      if (modoEdicion) {
        // ACTUALIZAR
        const nuevoStockTotal = stockActualBD + form.stock_calculado;
        // Si hay compra nueva, usamos el nuevo costo, sino mantenemos el anterior
        const nuevoCosto = form.cantidad_comprada > 0 ? form.costo_unitario_calculado : form.costo_unitario_calculado;

        await actualizarInsumo(form.id, {
          name: form.name,
          unit_measure: form.unit_measure,
          low_stock_threshold: form.low_stock_threshold,
          current_stock: nuevoStockTotal,
          unit_cost: nuevoCosto
        });

        // Registrar Historial solo si hubo compra
        if (form.cantidad_comprada > 0) {
            await registrarHistorialCompra(orgId!, descripcionHistorial, costoTotalCompra, form.fecha_compra);
        }

        toast.success(`Stock actualizado. Total: ${nuevoStockTotal} ${form.unit_measure}`);

      } else {
        // CREAR
        await crearInsumo({
          organization_id: orgId!,
          name: form.name,
          unit_measure: form.unit_measure,
          low_stock_threshold: form.low_stock_threshold,
          current_stock: form.stock_calculado,
          unit_cost: form.costo_unitario_calculado
        });

        // Registrar Historial Inicial
        if (form.cantidad_comprada > 0) {
            await registrarHistorialCompra(orgId!, descripcionHistorial, costoTotalCompra, form.fecha_compra);
        }
        
        toast.success("Insumo creado exitosamente");
      }
      
      setShowModal(false);
      cargarDatos();
    } catch (e: any) { 
        toast.error("Error al guardar");
        console.error(e);
    } finally { 
        setLoading(false); 
    }
  };

  const filtrados = insumos.filter(i => i.name.toLowerCase().includes(filtro.toLowerCase()));

  return (
    <div className="flex flex-col h-[calc(100vh-64px)] bg-stone-50 overflow-hidden">
      
      {/* Header */}
      <div className="bg-white border-b border-stone-200 px-6 py-5 flex flex-col md:flex-row md:items-center justify-between gap-4 shadow-sm z-10">
        <div>
          <h1 className="text-2xl font-bold text-stone-800 flex items-center gap-2">
            <Package className="text-emerald-600"/> Inventario de Insumos
          </h1>
          <p className="text-sm text-stone-500">Gestiona stock y costos de materia prima.</p>
        </div>
        
        <div className="flex gap-3 w-full md:w-auto">
          <div className="relative flex-1 md:w-72">
            <Search className="absolute left-3 top-3 text-stone-400" size={18}/>
            <input 
              className="w-full pl-10 p-2.5 border rounded-xl bg-stone-50 focus:bg-white focus:ring-2 focus:ring-emerald-500 transition-all outline-none text-sm"
              placeholder="Buscar insumo..."
              value={filtro}
              onChange={e => setFiltro(e.target.value)}
            />
          </div>
          <button onClick={abrirModalCrear} className="bg-stone-900 hover:bg-black text-white px-4 py-2.5 rounded-xl transition-all shadow-lg shadow-stone-200 flex items-center gap-2 font-bold">
            <Plus size={20}/> <span className="hidden md:inline">Nuevo</span>
          </button>
        </div>
      </div>

      {/* Grid de Insumos */}
      <div className="flex-1 overflow-y-auto p-6">
        {loading && insumos.length === 0 ? (
            <div className="flex justify-center items-center h-40 text-stone-400 gap-2">
                <div className="animate-spin w-5 h-5 border-2 border-current border-t-transparent rounded-full"/> Cargando...
            </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-5">
            {filtrados.map(item => {
              const stock = item.current_stock ?? 0;
              const umbral = item.low_stock_threshold ?? 0;
              const isLow = stock <= umbral;
              
              return (
                <div key={item.id} className={`bg-white p-5 rounded-2xl border transition-all group relative overflow-hidden ${isLow ? 'border-amber-200 shadow-amber-100' : 'border-stone-200 hover:border-emerald-400 hover:shadow-lg hover:shadow-emerald-50'}`}>
                  
                  {isLow && <div className="absolute top-0 right-0 w-16 h-16 bg-amber-100 rounded-bl-full -mr-8 -mt-8 z-0"></div>}

                  <div className="relative z-10">
                    <div className="flex justify-between items-start mb-3">
                      <div className="w-10 h-10 rounded-full bg-stone-50 flex items-center justify-center text-stone-600 group-hover:bg-emerald-50 group-hover:text-emerald-600 transition-colors">
                        <Package size={20}/>
                      </div>
                      {isLow && (
                        <span className="bg-amber-100 text-amber-700 text-[10px] font-bold px-2 py-1 rounded-full flex items-center gap-1">
                          <AlertTriangle size={10}/> BAJO
                        </span>
                      )}
                    </div>

                    <h3 className="font-bold text-stone-800 text-lg mb-1">{item.name}</h3>
                    <p className="text-xs text-stone-500 mb-4 bg-stone-50 inline-block px-2 py-1 rounded-lg border border-stone-100">
                      Costo Base: <strong>Bs {(item.unit_cost ?? 0).toFixed(5)}</strong> / {item.unit_measure}
                    </p>

                    <div className="flex justify-between items-end border-t border-stone-100 pt-4">
                      <div>
                        <p className="text-[10px] text-stone-400 uppercase font-bold tracking-wider">En Stock</p>
                        <p className={`text-2xl font-mono font-bold ${isLow ? 'text-amber-600' : 'text-stone-700'}`}>
                          {stock.toLocaleString()} <span className="text-sm font-sans font-normal text-stone-400">{item.unit_measure}</span>
                        </p>
                      </div>
                      <div className="flex gap-1">
                          <button onClick={() => abrirModalEditar(item)} className="p-2 text-stone-400 hover:text-emerald-600 hover:bg-emerald-50 rounded-lg transition-colors">
                              <Edit2 size={18}/>
                          </button>
                          <button onClick={() => { if(confirm('¿Eliminar?')) eliminarInsumo(item.id).then(cargarDatos) }} className="p-2 text-stone-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors">
                              <Trash2 size={18}/>
                          </button>
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* --- MODAL REDISEÑADO --- */}
      {showModal && (
        <div className="fixed inset-0 bg-stone-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-stone-50 rounded-3xl shadow-2xl w-full max-w-4xl overflow-hidden animate-in fade-in zoom-in-95 flex flex-col md:flex-row max-h-[90vh]">
            
            {/* LADO IZQUIERDO: DATOS DEL INSUMO */}
            <div className="w-full md:w-1/3 bg-white p-8 border-r border-stone-200 overflow-y-auto">
                <h3 className="font-bold text-lg text-stone-800 mb-1 flex items-center gap-2">
                    <Package className="text-emerald-600"/> Insumo
                </h3>
                <p className="text-xs text-stone-400 mb-6">Información básica del producto.</p>
                
                <div className="space-y-5">
                    <div>
                        <label className="text-xs font-bold text-stone-500 uppercase block mb-1">Nombre del Insumo</label>
                        <input className="w-full p-3 border border-stone-200 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none bg-stone-50 focus:bg-white transition-all" 
                            placeholder="Ej: Leche Entera" autoFocus
                            value={form.name} onChange={e => setForm({...form, name: e.target.value})} />
                    </div>

                    <div>
                        <label className="text-xs font-bold text-stone-500 uppercase block mb-1">Unidad de Medida (Receta)</label>
                        <select className="w-full p-3 border border-stone-200 rounded-xl outline-none bg-stone-50 focus:bg-white"
                            value={form.unit_measure} onChange={e => setForm({...form, unit_measure: e.target.value})}>
                            <option value="ml">Mililitros (ml)</option>
                            <option value="g">Gramos (g)</option>
                            <option value="kg">Kilogramos (kg)</option>
                            <option value="lt">Litros (l)</option>
                            <option value="und">Unidades (und)</option>
                        </select>
                        <p className="text-[10px] text-stone-400 mt-1 leading-tight">Define cómo se descontará este insumo en las recetas.</p>
                    </div>

                    <div>
                        <label className="text-xs font-bold text-stone-500 uppercase block mb-1">Stock Mínimo (Alerta)</label>
                        <input type="number" className="w-full p-3 border border-stone-200 rounded-xl outline-none bg-stone-50 focus:bg-white" 
                            value={form.low_stock_threshold} onChange={e => setForm({...form, low_stock_threshold: Number(e.target.value)})} />
                    </div>

                    {modoEdicion && (
                        <div className="p-4 bg-emerald-50 rounded-xl border border-emerald-100">
                            <p className="text-xs text-emerald-800 font-bold uppercase mb-1">Stock Actual en Sistema</p>
                            <p className="text-2xl font-mono text-emerald-700 font-bold">{stockActualBD.toLocaleString()} <span className="text-sm">{form.unit_measure}</span></p>
                        </div>
                    )}
                </div>
            </div>

            {/* LADO DERECHO: CALCULADORA DE COMPRA */}
            <div className="flex-1 p-8 bg-stone-50 overflow-y-auto">
                <div className="flex justify-between items-start mb-6">
                    <div>
                        <h3 className="font-bold text-lg text-stone-800 flex items-center gap-2">
                            <Calculator className="text-stone-600"/> Registrar Compra
                        </h3>
                        <p className="text-xs text-stone-400">Calcula el costo real y actualiza inventario.</p>
                    </div>
                    <button onClick={() => setShowModal(false)} className="p-2 hover:bg-stone-200 rounded-full text-stone-400 transition-colors"><X size={20}/></button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                    {/* Tarjeta de Entrada */}
                    <div className="bg-white p-5 rounded-2xl shadow-sm border border-stone-200 space-y-4">
                        <div className="flex items-center gap-2 text-stone-800 font-bold text-sm border-b border-stone-100 pb-2">
                           <span className="w-6 h-6 rounded-full bg-stone-100 flex items-center justify-center text-xs">1</span> Datos de Compra
                        </div>
                        
                        <div>
                           <label className="text-[10px] font-bold text-stone-400 uppercase">Fecha Compra</label>
                           <div className="relative">
                             <Calendar className="absolute left-3 top-2.5 text-stone-400" size={14}/>
                             <input type="date" className="w-full pl-9 p-2 border rounded-lg text-sm bg-stone-50 outline-none"
                               value={form.fecha_compra} onChange={e => setForm({...form, fecha_compra: e.target.value})} />
                           </div>
                        </div>

                        <div className="grid grid-cols-2 gap-3">
                            <div>
                                <label className="text-[10px] font-bold text-stone-400 uppercase">Presentación</label>
                                <input className="w-full p-2 border rounded-lg text-sm bg-stone-50 outline-none focus:bg-white focus:ring-2 focus:ring-emerald-500" placeholder="Ej: Caja" 
                                    value={form.presentacion_nombre} onChange={e => setForm({...form, presentacion_nombre: e.target.value})} />
                            </div>
                            <div>
                                <label className="text-[10px] font-bold text-stone-400 uppercase">Cant. Comprada</label>
                                <input type="number" className="w-full p-2 border rounded-lg text-sm bg-stone-50 outline-none focus:bg-white focus:ring-2 focus:ring-emerald-500" placeholder="0" 
                                    value={form.cantidad_comprada} onChange={e => setForm({...form, cantidad_comprada: Number(e.target.value)})} />
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-3">
                             <div>
                                <label className="text-[10px] font-bold text-stone-400 uppercase">Contenido ({form.unit_measure})</label>
                                <input type="number" className="w-full p-2 border rounded-lg text-sm bg-stone-50 outline-none focus:bg-white focus:ring-2 focus:ring-emerald-500" placeholder="Ej: 1000" 
                                    value={form.contenido_neto} onChange={e => setForm({...form, contenido_neto: Number(e.target.value)})} />
                             </div>
                             <div>
                                <label className="text-[10px] font-bold text-stone-400 uppercase">Costo Presentación</label>
                                <div className="relative">
                                    <span className="absolute left-2 top-2 text-stone-400 text-xs font-bold">Bs</span>
                                    <input type="number" className="w-full pl-6 p-2 border rounded-lg text-sm bg-stone-50 outline-none focus:bg-white focus:ring-2 focus:ring-emerald-500" placeholder="0.00" 
                                        value={form.costo_presentacion} onChange={e => setForm({...form, costo_presentacion: Number(e.target.value)})} />
                                </div>
                             </div>
                        </div>
                    </div>

                    {/* Tarjeta de Salida (Calculado) */}
                    <div className="bg-stone-800 text-stone-200 p-5 rounded-2xl shadow-lg flex flex-col justify-between">
                         <div>
                            <div className="flex items-center gap-2 text-white font-bold text-sm border-b border-stone-600 pb-2 mb-4">
                                <span className="w-6 h-6 rounded-full bg-emerald-500 text-white flex items-center justify-center text-xs">2</span> Resultado
                            </div>
                            
                            <div className="space-y-4">
                                <div className="flex justify-between items-center">
                                    <span className="text-xs text-stone-400">Stock a Agregar</span>
                                    <span className="text-xl font-mono font-bold text-white">+{form.stock_calculado.toLocaleString()} <span className="text-xs text-stone-400">{form.unit_measure}</span></span>
                                </div>
                                <div className="flex justify-between items-center">
                                    <span className="text-xs text-stone-400">Costo Unit. Real</span>
                                    <span className="text-xl font-mono font-bold text-emerald-400">Bs {form.costo_unitario_calculado.toFixed(5)}</span>
                                </div>
                                <div className="flex justify-between items-center pt-2 border-t border-stone-600">
                                    <span className="text-xs text-stone-400">Gasto Total</span>
                                    <span className="text-lg font-bold text-white">Bs {(form.cantidad_comprada * form.costo_presentacion).toFixed(2)}</span>
                                </div>
                            </div>
                         </div>
                         
                         <div className="mt-4 pt-4 border-t border-stone-600 text-[10px] text-stone-400 flex items-center gap-2">
                            <History size={12}/> Se registrará en Historial de Gastos
                         </div>
                    </div>
                </div>

                {/* Footer del Modal */}
                <div className="flex justify-end gap-3 pt-2">
                    <button onClick={() => setShowModal(false)} className="px-6 py-3 rounded-xl font-bold text-stone-500 hover:bg-stone-200 transition-colors">
                        Cancelar
                    </button>
                    <button onClick={handleGuardar} disabled={loading} className="px-8 py-3 bg-emerald-600 hover:bg-emerald-700 text-white rounded-xl font-bold shadow-xl shadow-emerald-200 transition-all flex items-center gap-2">
                        {loading ? 'Procesando...' : <>{modoEdicion ? 'Actualizar Stock' : 'Guardar Insumo'} <ArrowRight size={18}/></>}
                    </button>
                </div>

            </div>
          </div>
        </div>
      )}

    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useAuth } from '../hooks/useAuth';
import { getReports, getLotesParaAnalisis, createInternalReport, createExternalReport, type LabReportComplete, type LoteAnalisis } from '../services/laboratorioService';
import { TablaReportesLaboratorio } from '../components/TablaReportesLaboratorio';
import { VisualizadorReporte } from '../components/VisualizadorReporte';
import { FormularioMuestraExterna } from '../components/FormularioMuestraExterna';
import { FormularioAnalisisFisico } from '../components/FormularioAnalisisFisico';
import { FormularioCatacionSCA } from '../components/FormularioCatacionSCA';
import { ComparadorMuestras } from '../components/ComparadorMuestras';
import { Button } from '../components/ui';
import { Card } from '../components/ui/Card';
import { FlaskConical, Plus, Package, Building2, Filter, ArrowLeft, CheckCircle, Award, TrendingUp, GitCompare } from 'lucide-react';
import { toast } from 'sonner';

type Vista = 'dashboard' | 'detalle' | 'nuevoInterno' | 'nuevoExterno' | 'agregarAnalisis' | 'comparar';
type TipoAnalisis = 'fisico' | 'catacion' | null;

export function Laboratorio() {
  const { orgId } = useAuth();
  const [reportes, setReportes] = useState<LabReportComplete[]>([]);
  const [lotes, setLotes] = useState<LoteAnalisis[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [vistaActiva, setVistaActiva] = useState<Vista>('dashboard');
  const [reporteSeleccionado, setReporteSeleccionado] = useState<LabReportComplete | null>(null);
  const [reporteEnProceso, setReporteEnProceso] = useState<string | null>(null);
  const [tipoAnalisisActual, setTipoAnalisisActual] = useState<TipoAnalisis>(null);
  const [filtroTipo, setFiltroTipo] = useState<'todos' | 'internal' | 'external'>('todos');
  const [loteSeleccionado, setLoteSeleccionado] = useState('');
  const [reportesParaComparar, setReportesParaComparar] = useState<string[]>([]);

  useEffect(() => {
    cargarDatos();
  }, [orgId]);

  const cargarDatos = async () => {
    if (!orgId) return;
    setIsLoading(true);
    try {
      const [reportesData, lotesData] = await Promise.all([
        getReports(),
        getLotesParaAnalisis()
      ]);
      setReportes(reportesData);
      setLotes(lotesData);
    } catch (error) {
      toast.error('Error al cargar datos');
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleVerReporte = (reportId: string) => {
    const reporte = reportes.find(r => r.id === reportId);
    if (reporte) {
      setReporteSeleccionado(reporte);
      setVistaActiva('detalle');
    }
  };

  const handleCrearReporteInterno = async () => {
    if (!loteSeleccionado) {
      toast.warning('Selecciona un lote');
      return;
    }

    try {
      const reportId = await createInternalReport({
        report_date: new Date().toISOString().split('T')[0],
        analyst_name: '',
        sample_type: 'internal',
        batch_id: loteSeleccionado,
        report_type: 'complete'
      }, orgId!);

      setReporteEnProceso(reportId);
      setTipoAnalisisActual('fisico');
      setVistaActiva('agregarAnalisis');
      toast.success('Reporte creado. Agregando análisis físico...');
    } catch (error: any) {
      toast.error(error.message);
    }
  };

  const handleCrearReporteExterno = async (data: any) => {
    try {
      const reportId = await createExternalReport(data, orgId!);
      setReporteEnProceso(reportId);

      if (data.report_type === 'physical') {
        setTipoAnalisisActual('fisico');
        setVistaActiva('agregarAnalisis');
      } else if (data.report_type === 'cupping') {
        setTipoAnalisisActual('catacion');
        setVistaActiva('agregarAnalisis');
      } else {
        setTipoAnalisisActual('fisico');
        setVistaActiva('agregarAnalisis');
      }

      toast.success('Muestra externa registrada');
    } catch (error: any) {
      toast.error(error.message);
    }
  };

  const volverAlDashboard = () => {
    setVistaActiva('dashboard');
    setReporteSeleccionado(null);
    setReporteEnProceso(null);
    setTipoAnalisisActual(null);
    setLoteSeleccionado('');
    setReportesParaComparar([]);
    cargarDatos();
  };

  const toggleReporteComparar = (reportId: string) => {
    setReportesParaComparar(prev =>
      prev.includes(reportId)
        ? prev.filter(id => id !== reportId)
        : [...prev, reportId]
    );
  };

  const reportesFiltrados = reportes.filter(r => {
    if (filtroTipo === 'todos') return true;
    return r.sample_type === filtroTipo;
  });

  const estadisticas = {
    total: reportes.length,
    internas: reportes.filter(r => r.sample_type === 'internal').length,
    externas: reportes.filter(r => r.sample_type === 'external').length,
    specialty: reportes.filter(r => r.final_score && r.final_score >= 80).length,
    promedioScore: reportes.filter(r => r.final_score).length > 0
      ? (reportes.reduce((sum, r) => sum + (r.final_score || 0), 0) / reportes.filter(r => r.final_score).length)
      : 0
  };

  return (
    <div className="max-w-7xl mx-auto p-6">
      {/* Header */}
      <div className="mb-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold text-stone-800 flex items-center gap-3">
              <FlaskConical className="text-emerald-600" size={32} />
              Laboratorio de Café
            </h1>
            <p className="text-stone-600 mt-2">
              Sistema de análisis físico y sensorial (SCA)
            </p>
          </div>

          {vistaActiva !== 'dashboard' && (
            <Button
              icon={ArrowLeft}
              variant="secondary"
              onClick={volverAlDashboard}
            >
              Volver al Dashboard
            </Button>
          )}
        </div>
      </div>

      {/* Dashboard View */}
      {vistaActiva === 'dashboard' && (
        <>
          {/* Estadísticas */}
          <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mb-6">
            <Card className="p-4 hover:shadow-lg transition-shadow">
              <p className="text-xs font-bold text-stone-500 uppercase mb-1">Total Reportes</p>
              <p className="text-3xl font-black text-stone-800">{estadisticas.total}</p>
            </Card>
            <Card className="p-4 hover:shadow-lg transition-shadow">
              <p className="text-xs font-bold text-stone-500 uppercase mb-1">Internas</p>
              <p className="text-3xl font-black text-emerald-600">{estadisticas.internas}</p>
            </Card>
            <Card className="p-4 hover:shadow-lg transition-shadow">
              <p className="text-xs font-bold text-stone-500 uppercase mb-1">Externas</p>
              <p className="text-3xl font-black text-blue-600">{estadisticas.externas}</p>
            </Card>
            <Card className="p-4 hover:shadow-lg transition-shadow">
              <p className="text-xs font-bold text-stone-500 uppercase mb-1 flex items-center gap-1">
                <Award size={12} />
                Specialty
              </p>
              <p className="text-3xl font-black text-purple-600">{estadisticas.specialty}</p>
            </Card>
            <Card className="p-4 hover:shadow-lg transition-shadow">
              <p className="text-xs font-bold text-stone-500 uppercase mb-1 flex items-center gap-1">
                <TrendingUp size={12} />
                Promedio
              </p>
              <p className="text-3xl font-black text-amber-600">{estadisticas.promedioScore.toFixed(1)}</p>
            </Card>
          </div>

          {/* Crear Nuevo Reporte */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
            {/* Muestra Interna */}
            <Card className="p-6 hover:shadow-xl transition-all">
              <div className="flex items-start gap-4">
                <div className="p-3 bg-emerald-100 rounded-xl">
                  <Package className="text-emerald-600" size={24} />
                </div>
                <div className="flex-1">
                  <h3 className="font-bold text-lg text-stone-800 mb-1">Muestra Interna</h3>
                  <p className="text-sm text-stone-600 mb-4">Analizar lote de inventario</p>

                  <select
                    className="w-full p-3 border-2 border-stone-200 rounded-xl mb-3 font-semibold text-sm focus:border-emerald-500 outline-none"
                    value={loteSeleccionado}
                    onChange={(e) => setLoteSeleccionado(e.target.value)}
                  >
                    <option value="">-- Seleccionar Lote --</option>
                    {lotes.map(l => (
                      <option key={l.id} value={l.id}>
                        {l.codigo_lote} • {l.nombre_finca}
                      </option>
                    ))}
                  </select>

                  <Button
                    icon={Plus}
                    variant="primary"
                    fullWidth
                    onClick={handleCrearReporteInterno}
                    disabled={!loteSeleccionado}
                  >
                    Crear Reporte
                  </Button>
                </div>
              </div>
            </Card>

            {/* Muestra Externa */}
            <Card className="p-6 hover:shadow-xl transition-all">
              <div className="flex items-start gap-4">
                <div className="p-3 bg-blue-100 rounded-xl">
                  <Building2 className="text-blue-600" size={24} />
                </div>
                <div className="flex-1">
                  <h3 className="font-bold text-lg text-stone-800 mb-1">Muestra Externa</h3>
                  <p className="text-sm text-stone-600 mb-4">Analizar muestra de cliente</p>

                  <p className="text-xs text-stone-500 mb-3">
                    Registra muestras de clientes externos para análisis de calidad y certificación
                  </p>

                  <Button
                    icon={Plus}
                    variant="primary"
                    fullWidth
                    onClick={() => setVistaActiva('nuevoExterno')}
                  >
                    Nueva Muestra Externa
                  </Button>
                </div>
              </div>
            </Card>
          </div>

          {/* Filtros y Tabla */}
          <div className="mb-4 flex items-center gap-3">
            <Filter size={18} className="text-stone-400" />
            <div className="flex gap-2">
              {[
                { id: 'todos', label: 'Todos', icon: null },
                { id: 'internal', label: 'Internas', icon: Package },
                { id: 'external', label: 'Externas', icon: Building2 }
              ].map(filtro => {
                const Icon = filtro.icon;
                return (
                  <button
                    key={filtro.id}
                    onClick={() => setFiltroTipo(filtro.id as any)}
                    className={`px-4 py-2 rounded-lg font-bold text-sm transition-colors flex items-center gap-2 ${filtroTipo === filtro.id
                      ? 'bg-emerald-600 text-white shadow-lg'
                      : 'bg-stone-100 text-stone-600 hover:bg-stone-200'
                      }`}
                  >
                    {Icon && <Icon size={16} />}
                    {filtro.label}
                  </button>
                );
              })}
            </div>
            <span className="text-sm text-stone-500 ml-auto">
              {reportesFiltrados.length} {reportesFiltrados.length === 1 ? 'reporte' : 'reportes'}
            </span>
          </div>

          <Card>
            <TablaReportesLaboratorio
              reportes={reportesFiltrados}
              onViewReport={handleVerReporte}
              isLoading={isLoading}
            />
          </Card>
        </>
      )}

      {/* Vista Detalle */}
      {vistaActiva === 'detalle' && reporteSeleccionado && (
        <VisualizadorReporte reporte={reporteSeleccionado} />
      )}

      {/* Vista Nueva Muestra Externa */}
      {vistaActiva === 'nuevoExterno' && (
        <FormularioMuestraExterna
          onSubmit={handleCrearReporteExterno}
        />
      )}

      {/* Vista Agregar Análisis */}
      {vistaActiva === 'agregarAnalisis' && reporteEnProceso && (
        <div className="space-y-6">
          {/* Progress indicator */}
          <Card className="p-4 bg-emerald-50 border-emerald-200">
            <div className="flex items-center gap-3">
              <CheckCircle className="text-emerald-600" size={24} />
              <div>
                <p className="font-bold text-emerald-800">Reporte creado exitosamente</p>
                <p className="text-sm text-emerald-700">
                  {tipoAnalisisActual === 'fisico' ? 'Agregando análisis físico...' : 'Agregando catación SCA...'}
                </p>
              </div>
            </div>
          </Card>

          {tipoAnalisisActual === 'fisico' && (
            <FormularioAnalisisFisico
              onSubmit={async (data) => {
                // Implementar guardado
                toast.success('Análisis físico guardado');
                setTipoAnalisisActual('catacion');
              }}
            />
          )}

          {tipoAnalisisActual === 'catacion' && (
            <FormularioCatacionSCA
              onSubmit={async (data) => {
                // Implementar guardado
                toast.success('Catación guardada');
                volverAlDashboard();
              }}
            />
          )}

          <div className="flex gap-3">
            <Button
              variant="secondary"
              onClick={() => {
                if (tipoAnalisisActual === 'catacion') {
                  setTipoAnalisisActual('fisico');
                } else {
                  volverAlDashboard();
                }
              }}
            >
              ← Anterior
            </Button>

            <Button
              variant="outline"
              onClick={volverAlDashboard}
              className="ml-auto"
            >
              Guardar y Finalizar Después
            </Button>
          </div>
        </div>
      )}
    </div>
  );
}

import React from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { toast } from 'sonner';
import { supabase } from '../services/supabaseClient';
import { Coffee, Lock, Mail, ArrowRight, Loader2 } from 'lucide-react';
import { LoginSchema, LoginFormData } from '../utils/validationSchemas';

export function Login() {
  const navigate = useNavigate();

  const {
    register,
    handleSubmit,
    formState: { errors, isSubmitting }
  } = useForm<LoginFormData>({
    resolver: zodResolver(LoginSchema)
  });

  const onSubmit = async (data: LoginFormData) => {
    try {
      const { error } = await supabase.auth.signInWithPassword({
        email: data.email,
        password: data.password
      });

      if (error) throw error;
      navigate('/');
    } catch (error: any) {
      toast.error('Error de acceso', { description: error.message || 'Credenciales incorrectas' });
    }
  };

  return (
    <div className="min-h-screen bg-stone-900 flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-2xl shadow-2xl overflow-hidden">
        <div className="bg-emerald-900 p-8 text-center">
          <div className="w-16 h-16 bg-emerald-800 rounded-xl flex items-center justify-center mx-auto mb-4 shadow-lg">
            <Coffee size={32} className="text-emerald-100" />
          </div>
          <h1 className="text-2xl font-bold text-white">Trace Blend</h1>
          <p className="text-emerald-200 text-sm">Sistema de Gestión de Tostaduría</p>
        </div>

        <form onSubmit={handleSubmit(onSubmit)} className="p-8 space-y-6">
          <div className="space-y-4">
            {/* Campo Email */}
            <div>
              <div className="relative">
                <Mail className="absolute left-3 top-3 text-stone-400" size={18} />
                <input
                  type="email"
                  placeholder="Correo electrónico"
                  autoComplete="email"
                  className={`w-full pl-10 p-3 border rounded-xl outline-none transition-colors ${errors.email ? 'border-red-500 focus:border-red-500' : 'focus:border-emerald-500'
                    }`}
                  {...register('email')}
                />
              </div>
              {errors.email && (
                <p className="text-red-500 text-xs mt-1 ml-1">{errors.email.message}</p>
              )}
            </div>

            {/* Campo Password */}
            <div>
              <div className="relative">
                <Lock className="absolute left-3 top-3 text-stone-400" size={18} />
                <input
                  type="password"
                  placeholder="Contraseña"
                  autoComplete="current-password"
                  className={`w-full pl-10 p-3 border rounded-xl outline-none transition-colors ${errors.password ? 'border-red-500 focus:border-red-500' : 'focus:border-emerald-500'
                    }`}
                  {...register('password')}
                />
              </div>
              {errors.password && (
                <p className="text-red-500 text-xs mt-1 ml-1">{errors.password.message}</p>
              )}
            </div>
          </div>

          <div className="flex justify-end">
            <Link to="/recuperar" className="text-xs font-bold text-stone-500 hover:text-emerald-600">
              ¿Olvidaste tu contraseña?
            </Link>
          </div>

          <button
            type="submit"
            disabled={isSubmitting}
            className="w-full bg-stone-900 text-white py-3 rounded-xl font-bold flex justify-center items-center gap-2 hover:bg-black transition-all disabled:opacity-70 disabled:cursor-not-allowed"
          >
            {isSubmitting ? <Loader2 className="animate-spin" /> : <>Ingresar <ArrowRight size={18} /></>}
          </button>

          <div className="text-center pt-4 border-t border-stone-100">
            <p className="text-sm text-stone-500">
              ¿Aún no tienes cuenta? <Link to="/registro" className="font-bold text-emerald-600 hover:underline">Regístrate gratis</Link>
            </p>
          </div>
        </form>
      </div>
    </div>
  );
}

import React, { useState } from 'react';
import { useAuth } from '../hooks/useAuth';
import { supabase } from '../services/supabaseClient';
import { toast } from 'sonner';
import { Building2, Save, Upload, Coffee } from 'lucide-react';

export function Onboarding() {
  const { orgId, profile } = useAuth();
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({
    address: '',
    phone: '',
    currency_symbol: 'Bs',
    logo_file: null as File | null
  });

  const handleSave = async () => {
    if (!form.address || !form.phone) return toast.warning("Por favor completa los campos");
    if (!orgId) return;
    setLoading(true);

    try {
      let logoUrl = null;

      // 1. Subir Logo (si el usuario seleccionó uno)
      if (form.logo_file && orgId) {
        const fileExt = form.logo_file.name.split('.').pop();
        const fileName = `${orgId}-logo.${fileExt}`;
        
        const { error: uploadError } = await supabase.storage
          .from('logos')
          .upload(fileName, form.logo_file, { upsert: true });

        if (uploadError) throw uploadError;
        
        const { data: urlData } = supabase.storage.from('logos').getPublicUrl(fileName);
        logoUrl = urlData.publicUrl;
      }

      // 2. Actualizar Organización y Marcar como COMPLETADO
      const { error } = await supabase
        .from('organizations')
        .update({
          address: form.address,
          phone: form.phone,
          currency_symbol: form.currency_symbol,
          logo_url: logoUrl,
          
          setup_completed: true // <--- LA LLAVE QUE ABRE EL SISTEMA
        })
        .eq('id', orgId);

      if (error) throw error;

      toast.success("¡Todo listo! Bienvenido a TraceBlend.");
      // Recarga completa para refrescar el estado del Guardia y el Sidebar
      window.location.href = "/"; 

    } catch (e) {
      console.error(e);
      toast.error("Error al guardar la configuración");
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-stone-50 flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-2xl rounded-3xl shadow-xl overflow-hidden flex flex-col md:flex-row">
        
        <div className="bg-stone-900 w-full md:w-1/3 p-8 text-white flex flex-col justify-between">
          <div>
            <div className="w-12 h-12 bg-emerald-600 rounded-xl flex items-center justify-center mb-6">
              <Coffee size={24}/>
            </div>
            <h1 className="text-xl font-bold">Bienvenido, {profile?.first_name}</h1>
            <p className="text-stone-400 text-sm mt-2">Configura los datos básicos de tu tostaduría para comenzar.</p>
          </div>
          <div className="flex gap-2">
            <div className="w-2 h-2 rounded-full bg-emerald-500"></div>
            <div className="w-2 h-2 rounded-full bg-stone-700"></div>
          </div>
        </div>

        <div className="p-8 flex-1 space-y-5">
           <div>
             <label className="text-xs font-bold text-stone-400 uppercase">Moneda</label>
             <div className="flex gap-2 mt-2">
                {['Bs', '$us', '€'].map(sym => (
                  <button key={sym} onClick={() => setForm({...form, currency_symbol: sym})}
                    className={`px-3 py-2 rounded-lg border text-sm font-bold ${form.currency_symbol === sym ? 'bg-stone-800 text-white' : 'hover:bg-stone-50'}`}>
                    {sym}
                  </button>
                ))}
             </div>
           </div>

           <div>
             <label className="text-xs font-bold text-stone-400 uppercase">Dirección</label>
             <input className="w-full p-3 border rounded-xl mt-1 bg-stone-50" 
               placeholder="Ej: Av. Principal #123"
               value={form.address} onChange={e => setForm({...form, address: e.target.value})} />
           </div>

           <div>
             <label className="text-xs font-bold text-stone-400 uppercase">Teléfono</label>
             <input className="w-full p-3 border rounded-xl mt-1 bg-stone-50" 
               placeholder="+591 ..."
               value={form.phone} onChange={e => setForm({...form, phone: e.target.value})} />
           </div>

           <div>
             <label className="text-xs font-bold text-stone-400 uppercase">Logo</label>
             <div className="border-2 border-dashed border-stone-200 rounded-xl p-4 mt-1 text-center cursor-pointer hover:border-emerald-500 relative">
               <input type="file" accept="image/*" className="absolute inset-0 opacity-0 cursor-pointer"
                 onChange={e => setForm({...form, logo_file: e.target.files?.[0] || null})} />
               {form.logo_file ? <span className="text-emerald-600 font-bold">{form.logo_file.name}</span> : <span className="text-stone-400 text-xs">Subir imagen...</span>}
             </div>
           </div>

           <button onClick={handleSave} disabled={loading}
             className="w-full bg-emerald-600 text-white py-3 rounded-xl font-bold hover:bg-emerald-700 flex justify-center items-center gap-2 mt-2">
             {loading ? 'Guardando...' : <>Guardar y Entrar <Save size={18}/></>}
           </button>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Package, Search, Plus, Edit2, Tag, Coffee, Box, Utensils,
  Save, X, DollarSign, Barcode, List, Trash2
} from 'lucide-react';
import { useAuth } from '../hooks/useAuth';
import { toast } from 'sonner';
import {
  getTodosLosProductos, crearProducto, actualizarProducto,
  getInsumosDisponibles, getRecetaProducto,
  ProductoForm, IngredienteReceta
} from '../services/productosService';
import { EmptyState, Button } from '../components/ui';

// Categorías Visuales
const CAT_ICONS: Record<string, any> = {
  'Café': Coffee, 'Grano': Package, 'Pastelería': Utensils, 'Accesorios': Box, 'General': Tag
};

export function Productos() {
  const { orgId } = useAuth();
  const [loading, setLoading] = useState(true);
  const [productos, setProductos] = useState<any[]>([]);
  const [insumos, setInsumos] = useState<any[]>([]); // Lista de insumos disponibles

  const [filtro, setFiltro] = useState('');
  const [catFiltro, setCatFiltro] = useState('Todas');
  const [showModal, setShowModal] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [selectedId, setSelectedId] = useState<string | null>(null);

  // Formulario Principal
  const [formData, setFormData] = useState<ProductoForm>({
    name: '', sku: '', sale_price: '', category: 'General',
    is_roasted: false, package_weight_grams: '', stock_inicial: '',
    receta: []
  });

  // Estado temporal para agregar ingrediente
  const [newIngrediente, setNewIngrediente] = useState<{ id: string, qty: string }>({ id: '', qty: '' });

  useEffect(() => {
    if (orgId) {
      cargar();
      getInsumosDisponibles(orgId).then(setInsumos);
    }
  }, [orgId]);

  const cargar = async () => {
    setLoading(true);
    try {
      const data = await getTodosLosProductos(orgId!);
      setProductos(data);
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  };

  const handleSave = async () => {
    if (!formData.name || !formData.sale_price) return toast.warning("Nombre y Precio requeridos");
    try {
      if (isEditing && selectedId) {
        await actualizarProducto(selectedId, formData, orgId!);
        toast.success("Producto actualizado");
      } else {
        await crearProducto(formData, orgId!);
        toast.success("Producto creado");
      }
      setShowModal(false);
      resetForm();
      cargar();
    } catch (e: any) { toast.error(e.message); }
  };

  const openEdit = async (p: any) => {
    // Cargar receta existente
    let recetaActual: IngredienteReceta[] = [];
    try {
      recetaActual = await getRecetaProducto(p.id);
    } catch (e) { console.error("Error cargando receta", e); }

    setFormData({
      name: p.name,
      sku: p.sku || '',
      sale_price: p.sale_price,
      category: p.category || 'General',
      is_roasted: p.is_roasted,
      package_weight_grams: p.package_weight_grams || '',
      stock_inicial: '',
      receta: recetaActual
    });
    setSelectedId(p.id);
    setIsEditing(true);
    setShowModal(true);
  };

  const resetForm = () => {
    setFormData({
      name: '', sku: '', sale_price: '', category: 'General',
      is_roasted: false, package_weight_grams: '', stock_inicial: '', receta: []
    });
    setNewIngrediente({ id: '', qty: '' });
    setIsEditing(false);
    setSelectedId(null);
  };

  // --- Helpers de Receta ---
  const agregarIngrediente = () => {
    if (!newIngrediente.id || !newIngrediente.qty) return;
    const insumoReal = insumos.find(i => i.id === newIngrediente.id);
    if (!insumoReal) return;

    const item: IngredienteReceta = {
      supply_id: newIngrediente.id,
      quantity: Number(newIngrediente.qty),
      nombre_insumo: insumoReal.name,
      unidad: insumoReal.unit_measure
    };

    setFormData({ ...formData, receta: [...(formData.receta || []), item] });
    setNewIngrediente({ id: '', qty: '' });
  };

  const quitarIngrediente = (index: number) => {
    const nuevaReceta = [...(formData.receta || [])];
    nuevaReceta.splice(index, 1);
    setFormData({ ...formData, receta: nuevaReceta });
  };

  // Filtrado
  const filtrados = productos.filter(p => {
    const matchText = p.name.toLowerCase().includes(filtro.toLowerCase()) || p.sku?.toLowerCase().includes(filtro.toLowerCase());
    const matchCat = catFiltro === 'Todas' || p.category === catFiltro;
    return matchText && matchCat;
  });
  const categoriasUnicas = ['Todas', ...new Set(productos.map(p => p.category || 'General'))];

  return (
    <div className="flex flex-col h-[calc(100vh-64px)] bg-stone-50 overflow-hidden">

      {/* HEADER */}
      <div className="bg-white border-b border-stone-200 px-6 py-4 flex justify-between items-center gap-4 shadow-sm">
        <div>
          <h1 className="text-2xl font-bold text-stone-800 flex items-center gap-2">
            <Package className="text-emerald-600" /> Catálogo Maestro
          </h1>
          <p className="text-xs text-stone-500">Define productos y sus fichas técnicas.</p>
        </div>
        <button onClick={() => { resetForm(); setShowModal(true); }} className="bg-stone-900 text-white px-4 py-2 rounded-xl flex items-center gap-2 font-bold shadow-lg hover:bg-black transition-all">
          <Plus size={20} /> Nuevo
        </button>
      </div>

      {/* FILTROS */}
      <div className="px-6 py-2 bg-stone-50 border-b border-stone-200 flex gap-2 overflow-x-auto no-scrollbar items-center">
        <div className="relative w-64 mr-4">
          <Search className="absolute left-3 top-2.5 text-stone-400" size={16} />
          <input className="w-full pl-9 p-2 border rounded-lg bg-white text-sm" placeholder="Buscar..." value={filtro} onChange={e => setFiltro(e.target.value)} />
        </div>
        {categoriasUnicas.map(cat => (
          <button key={cat} onClick={() => setCatFiltro(cat)} className={`px-3 py-1 rounded-full text-xs font-bold whitespace-nowrap border ${catFiltro === cat ? 'bg-stone-800 text-white border-stone-800' : 'bg-white text-stone-500 border-stone-200'}`}>
            {cat}
          </button>
        ))}
      </div>

      {/* GRID PRODUCTOS */}
      <div className="flex-1 overflow-y-auto p-6">
        {filtrados.length === 0 ? (
          <EmptyState
            icon={Package}
            title="No hay productos registrados"
            description={
              filtro
                ? `No se encontraron productos que coincidan con "${filtro}". Intenta con otro término.`
                : catFiltro !== 'Todas'
                  ? `No hay productos en la categoría "${catFiltro}". Prueba con otra categoría.`
                  : 'Comienza creando tu primer producto para empezar a vender.'
            }
            actionLabel="Crear Producto"
            onAction={() => { resetForm(); setShowModal(true); }}
            secondaryActionLabel={catFiltro !== 'Todas' || filtro ? 'Limpiar Filtros' : undefined}
            onSecondaryAction={catFiltro !== 'Todas' || filtro ? () => { setCatFiltro('Todas'); setFiltro(''); } : undefined}
          />
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
            {filtrados.map(p => {
              const Icon = CAT_ICONS[p.category] || Tag;
              return (
                <div key={p.id} className="bg-white p-4 rounded-xl border border-stone-200 shadow-sm hover:shadow-md transition-smooth group relative flex flex-col justify-between animate-fade-in">
                  <div>
                    <div className="flex justify-between items-start mb-2">
                      <div className="flex items-center gap-3">
                        <div className={`w-10 h-10 rounded-lg flex items-center justify-center ${p.is_roasted ? 'bg-amber-50 text-amber-700' : 'bg-stone-100 text-stone-600'}`}>
                          <Icon size={20} />
                        </div>
                        <div>
                          <h3 className="font-bold text-stone-800 leading-tight">{p.name}</h3>
                          <span className="text-[10px] text-stone-400 uppercase font-bold tracking-wider">{p.category}</span>
                        </div>
                      </div>
                    </div>
                    {p.sku && <p className="text-xs text-stone-400 font-mono flex items-center gap-1 mb-2"><Barcode size={10} /> {p.sku}</p>}
                  </div>

                  <div className="pt-3 border-t border-stone-100 flex justify-between items-end">
                    <button onClick={() => openEdit(p)} className="text-stone-400 hover:text-emerald-600 font-bold text-xs flex items-center gap-1 transition-smooth">
                      <Edit2 size={12} /> Editar
                    </button>
                    <p className="text-xl font-bold text-stone-800">Bs {p.sale_price}</p>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* MODAL */}
      {showModal && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-2xl rounded-2xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="px-6 py-4 border-b border-stone-100 flex justify-between items-center bg-stone-50">
              <h3 className="font-bold text-lg text-stone-800">{isEditing ? 'Editar Producto' : 'Nuevo Producto'}</h3>
              <button onClick={() => setShowModal(false)} className="p-1 rounded-full hover:bg-stone-200"><X size={20} /></button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-6">

              {/* DATOS BÁSICOS */}
              <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2">
                  <label className="text-xs font-bold text-stone-400 uppercase">Nombre</label>
                  <input className="w-full p-2 border rounded-lg mt-1" placeholder="Ej: Cappuccino" value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} />
                </div>
                <div>
                  <label className="text-xs font-bold text-stone-400 uppercase">Categoría</label>
                  <select className="w-full p-2 border rounded-lg mt-1 bg-white" value={formData.category} onChange={e => setFormData({ ...formData, category: e.target.value })}>
                    <option value="General">General</option>
                    <option value="Café">Bebidas Café</option>
                    <option value="Grano">Grano / Bolsas</option>
                    <option value="Pastelería">Pastelería</option>
                    <option value="Accesorios">Accesorios</option>
                  </select>
                </div>
                <div>
                  <label className="text-xs font-bold text-stone-400 uppercase">Precio (Bs)</label>
                  <div className="relative mt-1">
                    <DollarSign size={14} className="absolute left-2 top-3 text-stone-400" />
                    <input type="number" className="w-full pl-6 p-2 border rounded-lg font-bold" value={formData.sale_price} onChange={e => setFormData({ ...formData, sale_price: e.target.value })} />
                  </div>
                </div>
              </div>

              {/* SECCIÓN FICHA TÉCNICA (RECETA) */}
              {!formData.is_roasted && (
                <div className="bg-stone-50 p-4 rounded-xl border border-stone-200">
                  <h4 className="font-bold text-stone-700 mb-3 flex items-center gap-2">
                    <List size={16} className="text-emerald-600" /> Ficha Técnica (Receta)
                  </h4>
                  <p className="text-xs text-stone-500 mb-4">Define qué insumos se descuentan al vender este producto.</p>

                  {/* Agregar Item */}
                  <div className="flex gap-2 mb-4">
                    <select className="flex-1 p-2 border rounded-lg text-sm" value={newIngrediente.id} onChange={e => setNewIngrediente({ ...newIngrediente, id: e.target.value })}>
                      <option value="">+ Agregar Insumo...</option>
                      {insumos.map(i => <option key={i.id} value={i.id}>{i.name} ({i.unit_measure})</option>)}
                    </select>
                    <input
                      type="number"
                      className="w-20 p-2 border rounded-lg text-sm"
                      placeholder="Cant."
                      value={newIngrediente.qty}
                      onChange={e => setNewIngrediente({ ...newIngrediente, qty: e.target.value })}
                    />
                    <button onClick={agregarIngrediente} className="bg-stone-800 text-white px-3 rounded-lg font-bold hover:bg-black">+</button>
                  </div>

                  {/* Lista Items */}
                  {formData.receta && formData.receta.length > 0 ? (
                    <div className="space-y-2">
                      {formData.receta.map((r, idx) => (
                        <div key={idx} className="flex justify-between items-center bg-white p-2 rounded border border-stone-200 text-sm">
                          <span>{r.nombre_insumo}</span>
                          <div className="flex items-center gap-3">
                            <span className="font-mono font-bold text-stone-600">{r.quantity} {r.unidad}</span>
                            <button onClick={() => quitarIngrediente(idx)} className="text-red-400 hover:text-red-600"><Trash2 size={14} /></button>
                          </div>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <div className="text-center py-4 text-xs text-stone-400 italic border-2 border-dashed border-stone-200 rounded-lg">
                      No hay ingredientes definidos.
                    </div>
                  )}
                </div>
              )}

              {/* CHECKBOX CAFÉ TOSTADO */}
              <div className="pt-2 border-t border-stone-100">
                <label className="flex items-center gap-2 cursor-pointer">
                  <input type="checkbox" className="accent-emerald-600" checked={formData.is_roasted} onChange={e => setFormData({ ...formData, is_roasted: e.target.checked })} />
                  <span className="text-sm font-bold text-stone-600">Es Café Tostado (Bolsa para venta)</span>
                </label>
                {formData.is_roasted && (
                  <div className="mt-2 ml-6">
                    <label className="text-xs font-bold text-stone-400 uppercase">Peso Neto (Gramos)</label>
                    <input type="number" className="block w-32 p-2 border rounded-lg mt-1" value={formData.package_weight_grams} onChange={e => setFormData({ ...formData, package_weight_grams: e.target.value })} />
                  </div>
                )}
              </div>

            </div>

            <div className="p-4 bg-stone-50 border-t border-stone-100 flex gap-3">
              <button onClick={() => setShowModal(false)} className="flex-1 py-3 text-stone-500 font-bold hover:bg-stone-200 rounded-xl transition-colors">Cancelar</button>
              <button onClick={handleSave} className="flex-1 py-3 bg-stone-900 text-white rounded-xl font-bold shadow-lg hover:bg-black transition-colors flex justify-center gap-2">
                <Save size={18} /> Guardar Producto
              </button>
            </div>
          </div>
        </div>
      )}

    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useAuth } from '../hooks/useAuth';
import { getPromociones, crearPromocion, toggleEstadoPromocion, eliminarPromocion, Promocion } from '../services/promocionesService';
import { getTodosLosProductos as getProductos } from '../services/productosService'; 
import { toast } from 'sonner';
import { Plus, Trash2, Tag, Power, X, Gift, Percent, Users, Calendar } from 'lucide-react';

export function Promociones() {
  const { orgId } = useAuth();
  const [promociones, setPromociones] = useState<Promocion[]>([]);
  const [productos, setProductos] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [showModal, setShowModal] = useState(false);

  // Formulario y Tipo de Promoción
  const [tipoPromo, setTipoPromo] = useState<'producto' | 'convenio'>('producto');
  const [form, setForm] = useState({
    name: '',
    product_id: '' as string | null,
    discount_percent: 0,
    is_courtesy: false,
    start_date: new Date().toISOString().slice(0, 16), // Formato para input datetime-local
    end_date: ''
  });

  useEffect(() => {
    if (orgId) cargarDatos();
  }, [orgId]);

  const cargarDatos = async () => {
    if (!orgId) return;
    setLoading(true);
    try {
      const [promos, prods] = await Promise.all([
        getPromociones(), 
        getProductos(orgId)
      ]);
      setPromociones(promos);
      setProductos(prods);
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  };

  const handleGuardar = async () => {
    if (!form.name || !form.start_date || !form.end_date) return toast.warning("Datos incompletos");
    if (tipoPromo === 'producto' && !form.product_id) return toast.warning("Selecciona un producto");

    try {
      await crearPromocion({
        name: form.name,
        // Lógica clave: Si es convenio, product_id es null
        product_id: tipoPromo === 'producto' ? form.product_id : null,
        discount_percent: form.discount_percent,
        is_courtesy: form.is_courtesy,
        start_date: form.start_date,
        end_date: form.end_date,
        is_active: true
      }, orgId!);
      
      toast.success(tipoPromo === 'convenio' ? "Convenio Global Creado" : "Oferta de Producto Creada");
      setShowModal(false);
      
      // Reset del formulario
      setForm({ 
        name: '', 
        product_id: '', 
        discount_percent: 0, 
        is_courtesy: false, 
        start_date: new Date().toISOString().slice(0, 16), 
        end_date: '' 
      });
      cargarDatos();
    } catch (e: any) { toast.error(e.message); }
  };

  const handleToggle = async (p: Promocion) => {
    try { await toggleEstadoPromocion(p.id, p.is_active); cargarDatos(); } catch (e) { toast.error("Error"); }
  };

  const handleEliminar = async (id: string) => {
    if (!confirm("¿Eliminar?")) return;
    try { await eliminarPromocion(id); cargarDatos(); } catch (e) { toast.error("Error"); }
  };

  return (
    <div className="p-6 bg-stone-50 min-h-screen">
      
      {/* Header */}
      <div className="flex justify-between items-center mb-6">
        <div>
          <h1 className="text-2xl font-bold text-stone-800">Promociones y Convenios</h1>
          <p className="text-stone-500">Gestiona ofertas automáticas y descuentos globales.</p>
        </div>
        <button onClick={() => setShowModal(true)} className="bg-stone-900 text-white px-4 py-2 rounded-xl font-bold flex items-center gap-2 hover:bg-black transition-all shadow-lg shadow-stone-200">
          <Plus size={20}/> Nuevo
        </button>
      </div>

      {/* Grid de Promociones */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {promociones.map(p => (
          <div key={p.id} className={`bg-white p-5 rounded-2xl border relative transition-all ${p.is_active ? 'border-stone-200 shadow-sm hover:shadow-md' : 'border-stone-100 opacity-60 grayscale'}`}>
            
            {/* Badge Tipo */}
            <div className={`absolute top-0 right-0 px-3 py-1 rounded-bl-xl text-[10px] font-bold uppercase tracking-wider ${p.product_id ? 'bg-blue-50 text-blue-600' : 'bg-purple-50 text-purple-600'}`}>
                {p.product_id ? 'Producto' : 'Convenio Global'}
            </div>

            <div className="flex justify-between items-start mb-4 mt-2">
              <div className="flex items-center gap-3">
                <div className={`w-12 h-12 rounded-xl flex items-center justify-center ${p.product_id ? 'bg-blue-100 text-blue-600' : 'bg-purple-100 text-purple-600'}`}>
                   {p.product_id ? <Tag size={24}/> : <Users size={24}/>}
                </div>
                <div>
                  <h3 className="font-bold text-stone-800 leading-tight text-lg">{p.name}</h3>
                  <p className="text-xs text-stone-500 mt-0.5">{p.products?.name || 'Aplica a toda la cuenta'}</p>
                </div>
              </div>
            </div>

            <div className="bg-stone-50 p-3 rounded-xl text-sm space-y-2 mb-4 border border-stone-100">
               <div className="flex justify-between items-center">
                 <span className="text-stone-500">Beneficio:</span> 
                 <span className={`font-bold px-2 py-0.5 rounded ${p.is_courtesy ? 'bg-emerald-100 text-emerald-700' : 'bg-stone-200 text-stone-800'}`}>
                    {p.is_courtesy ? '100% GRATIS' : `-${p.discount_percent}% OFF`}
                 </span>
               </div>
               <div className="flex justify-between items-center">
                 <span className="text-stone-500 flex items-center gap-1"><Calendar size={12}/> Vence:</span> 
                 <span className="font-medium text-stone-700">{new Date(p.end_date).toLocaleDateString()}</span>
               </div>
            </div>

            <div className="flex justify-end gap-2 pt-2 border-t border-stone-100">
               <button onClick={() => handleToggle(p)} className={`p-2 rounded-lg transition-colors ${p.is_active ? 'text-emerald-600 hover:bg-emerald-50' : 'text-stone-400 hover:text-stone-600 hover:bg-stone-100'}`} title={p.is_active ? "Desactivar" : "Activar"}>
                 <Power size={20}/>
               </button>
               <button onClick={() => handleEliminar(p.id)} className="p-2 text-stone-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors" title="Eliminar">
                 <Trash2 size={20}/>
               </button>
            </div>
          </div>
        ))}
        
        {promociones.length === 0 && !loading && (
            <div className="col-span-full py-12 text-center text-stone-400 border-2 border-dashed border-stone-200 rounded-2xl">
                <Tag size={40} className="mx-auto mb-2 opacity-20"/>
                <p>No hay promociones registradas</p>
            </div>
        )}
      </div>

      {/* MODAL CREAR */}
      {showModal && (
        <div className="fixed inset-0 bg-stone-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden animate-in fade-in zoom-in-95">
            <div className="p-5 border-b border-stone-100 flex justify-between items-center bg-stone-50">
                <h3 className="font-bold text-lg text-stone-800">Nueva Promoción</h3>
                <button onClick={() => setShowModal(false)} className="p-1 hover:bg-stone-200 rounded-full transition-colors"><X size={20} className="text-stone-400"/></button>
            </div>
            
            <div className="p-6 space-y-5">
              {/* Switch Tipo */}
              <div className="flex bg-stone-100 p-1 rounded-xl">
                  <button onClick={() => setTipoPromo('producto')} className={`flex-1 py-2.5 text-sm font-bold rounded-lg transition-all flex items-center justify-center gap-2 ${tipoPromo==='producto' ? 'bg-white shadow text-stone-800' : 'text-stone-400 hover:text-stone-600'}`}>
                    <Tag size={16}/> Oferta Producto
                  </button>
                  <button onClick={() => setTipoPromo('convenio')} className={`flex-1 py-2.5 text-sm font-bold rounded-lg transition-all flex items-center justify-center gap-2 ${tipoPromo==='convenio' ? 'bg-white shadow text-purple-700' : 'text-stone-400 hover:text-stone-600'}`}>
                    <Users size={16}/> Convenio Global
                  </button>
              </div>

              <div>
                <label className="text-xs font-bold text-stone-500 uppercase ml-1">Nombre</label>
                <input className="w-full p-3 border border-stone-200 rounded-xl mt-1 focus:ring-2 focus:ring-stone-800 outline-none transition-all" 
                  placeholder={tipoPromo==='convenio' ? "Ej: Convenio Librería, Club de Lectura..." : "Ej: Happy Hour, 2x1..."} 
                  value={form.name} onChange={e => setForm({...form, name: e.target.value})} />
              </div>

              {tipoPromo === 'producto' && (
                <div>
                    <label className="text-xs font-bold text-stone-500 uppercase ml-1">Producto</label>
                    <select className="w-full p-3 border border-stone-200 rounded-xl mt-1 bg-white outline-none" 
                      value={form.product_id || ''} onChange={e => setForm({...form, product_id: e.target.value})}>
                      <option value="">Seleccionar producto...</option>
                      {productos.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                    </select>
                </div>
              )}

              <div className="grid grid-cols-2 gap-4">
                 <div>
                    <label className="text-xs font-bold text-stone-500 uppercase ml-1">Beneficio</label>
                    <div className="flex gap-2 mt-1">
                        <button onClick={() => setForm({...form, is_courtesy: false})} className={`flex-1 py-3 rounded-xl border font-bold text-sm transition-all ${!form.is_courtesy ? 'border-stone-800 bg-stone-50 text-stone-800' : 'border-stone-200 text-stone-400'}`}>
                            % Off
                        </button>
                        <button onClick={() => setForm({...form, is_courtesy: true, discount_percent: 100})} className={`flex-1 py-3 rounded-xl border font-bold text-sm transition-all ${form.is_courtesy ? 'border-emerald-500 bg-emerald-50 text-emerald-700' : 'border-stone-200 text-stone-400'}`}>
                            Gratis
                        </button>
                    </div>
                 </div>
                 {!form.is_courtesy && (
                   <div>
                      <label className="text-xs font-bold text-stone-500 uppercase ml-1">Porcentaje</label>
                      <div className="relative mt-1">
                        <input type="number" className="w-full p-3 border border-stone-200 rounded-xl outline-none text-center font-bold text-lg" placeholder="20"
                            value={form.discount_percent} onChange={e => setForm({...form, discount_percent: Number(e.target.value)})} />
                        <span className="absolute right-4 top-4 text-stone-400 font-bold">%</span>
                      </div>
                   </div>
                 )}
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                   <label className="text-xs font-bold text-stone-500 uppercase ml-1">Desde</label>
                   <input type="datetime-local" className="w-full p-3 border border-stone-200 rounded-xl mt-1 text-sm bg-white"
                     value={form.start_date} onChange={e => setForm({...form, start_date: e.target.value})} />
                </div>
                <div>
                   <label className="text-xs font-bold text-stone-500 uppercase ml-1">Hasta</label>
                   <input type="datetime-local" className="w-full p-3 border border-stone-200 rounded-xl mt-1 text-sm bg-white"
                     value={form.end_date} onChange={e => setForm({...form, end_date: e.target.value})} />
                </div>
              </div>

              <button onClick={handleGuardar} className="w-full bg-stone-900 text-white py-4 rounded-xl font-bold hover:bg-black transition-all shadow-xl shadow-stone-200 mt-2 flex justify-center items-center gap-2">
                Guardar Promoción
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useAuth } from '../hooks/useAuth';
import {
  getProveedores,
  crearProveedor,
  getProveedorCompleto,
  actualizarProveedor
} from '../services/proveedoresService';
import { ProveedorFormData } from '../utils/validationSchemas';
import { toast } from 'sonner';
import { Truck, Plus, MapPin, User, Loader2, Package, Edit2, Navigation } from 'lucide-react';
import { MapPicker } from '../components/MapPicker';

interface ProveedorForm {
  nombre_completo: string;
  ci_nit: string;
  tipo_proveedor: string;
  nombre_finca: string;
  pais: string;
  region: string;
  sub_region: string;
  altura_msnm: string | number;
  latitude?: number;
  longitude?: number;
}

export function Proveedores() {
  const { orgId } = useAuth();
  const [list, setList] = useState<any[]>([]);
  const [showModal, setShowModal] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [editingIds, setEditingIds] = useState<{ supplierId: string; farmId: string } | null>(null);

  const [form, setForm] = useState<ProveedorForm>({
    nombre_completo: '', ci_nit: '', tipo_proveedor: 'productor', nombre_finca: '',
    pais: 'Bolivia', region: '', sub_region: '', altura_msnm: ''
  });

  const [mapCoords, setMapCoords] = useState<{ lat: number; lng: number } | null>(null);

  useEffect(() => { if (orgId) load(); }, [orgId]);

  const load = () => getProveedores().then(setList);

  const handleNew = () => {
    setIsEditing(false);
    setEditingIds(null);
    setForm({
      nombre_completo: '', ci_nit: '', tipo_proveedor: 'productor', nombre_finca: '',
      pais: 'Bolivia', region: '', sub_region: '', altura_msnm: ''
    });
    setMapCoords(null);
    setShowModal(true);
  };

  const handleEdit = async (supplierId: string, farmId: string) => {
    setIsLoading(true);
    try {
      const data = await getProveedorCompleto(supplierId, farmId);

      setForm({
        nombre_completo: data.supplier.name,
        ci_nit: data.supplier.tax_id,
        tipo_proveedor: data.supplier.type,
        nombre_finca: data.farm.name,
        pais: data.farm.country_code || 'Bolivia',
        region: data.farm.region || '',
        sub_region: data.farm.sub_region || '',
        altura_msnm: data.farm.altitude_masl || ''
      });

      if (data.farm.latitude && data.farm.longitude) {
        setMapCoords({ lat: data.farm.latitude, lng: data.farm.longitude });
      } else {
        setMapCoords(null);
      }

      setIsEditing(true);
      setEditingIds({ supplierId, farmId });
      setShowModal(true);
    } catch (e: any) {
      toast.error('Error al cargar proveedor', { description: e.message });
    } finally {
      setIsLoading(false);
    }
  };

  const handleSave = async () => {
    // Validación simple
    if (!form.nombre_completo || !form.ci_nit || !form.nombre_finca) {
      toast.error("Completa los campos requeridos");
      return;
    }

    setIsLoading(true);
    try {
      const formData: ProveedorFormData = {
        nombre_completo: form.nombre_completo,
        ci_nit: form.ci_nit,
        tipo_proveedor: form.tipo_proveedor as 'productor' | 'cooperativa' | 'importador',
        nombre_finca: form.nombre_finca,
        pais: form.pais,
        region: form.region,
        sub_region: form.sub_region,
        altura_msnm: typeof form.altura_msnm === 'string' ? parseFloat(form.altura_msnm) : form.altura_msnm,
        latitude: mapCoords?.lat,
        longitude: mapCoords?.lng
      };

      if (isEditing && editingIds) {
        await actualizarProveedor(editingIds.supplierId, editingIds.farmId, formData);
        toast.success("Proveedor actualizado exitosamente");
      } else {
        await crearProveedor(formData, orgId!);
        toast.success("Proveedor registrado exitosamente");
      }

      setShowModal(false);
      setForm({
        nombre_completo: '', ci_nit: '', tipo_proveedor: 'productor', nombre_finca: '',
        pais: 'Bolivia', region: '', sub_region: '', altura_msnm: ''
      });
      setMapCoords(null);
      setIsEditing(false);
      setEditingIds(null);
      load();
    } catch (e: any) {
      toast.error(isEditing ? "Error al actualizar proveedor" : "Error al guardar proveedor", {
        description: e.message || "Verifica que los datos sean correctos"
      });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="p-6 h-[calc(100vh-64px)] bg-stone-50 overflow-hidden flex flex-col">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-2xl font-bold text-stone-800 flex items-center gap-2">
          <Truck className="text-amber-600" /> Proveedores
        </h1>
        <button
          onClick={handleNew}
          className="bg-stone-900 text-white px-4 py-2 rounded-xl flex items-center gap-2 font-bold shadow hover:bg-black"
        >
          <Plus size={18} /> Nuevo
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 overflow-y-auto pb-20">
        {list.length === 0 ? (
          <div className="col-span-full flex flex-col items-center justify-center py-16 text-center">
            <Package className="w-16 h-16 text-stone-300 mb-4" />
            <p className="text-stone-500 font-bold text-lg">No hay proveedores registrados</p>
            <p className="text-sm text-stone-400 mt-2">
              Comienza creando tu primer proveedor con el botón "Nuevo"
            </p>
          </div>
        ) : (
          list.map((p, i) => (
            <div key={i} className="bg-white p-5 rounded-xl border border-stone-200 shadow-sm hover:shadow-md transition-shadow relative">
              <div className="flex justify-between items-start mb-2">
                <h3 className="font-bold text-stone-800 text-lg flex items-center gap-2">
                  <User size={18} className="text-stone-400" /> {p.nombre_mostrar.split('-')[0]}
                </h3>
                {p.finca_id && (
                  <button
                    onClick={() => handleEdit(p.id, p.finca_id)}
                    className="text-blue-600 hover:text-blue-800 p-1 rounded hover:bg-blue-50 transition-colors"
                    title="Editar proveedor"
                  >
                    <Edit2 size={16} />
                  </button>
                )}
              </div>

              {p.finca_id && (
                <div className="mt-3 pl-2 border-l-2 border-amber-200 space-y-1">
                  <p className="text-sm font-bold text-amber-800 flex items-center gap-1">
                    <MapPin size={14} /> {p.nombre_mostrar.split('-')[1] || 'Finca'}
                  </p>
                  {p.hasCoordinates && (
                    <p className="text-xs text-emerald-600 flex items-center gap-1">
                      <Navigation size={12} /> Ubicación GPS registrada
                    </p>
                  )}
                </div>
              )}
            </div>
          ))
        )}
      </div>

      {showModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
          <div className="bg-white p-6 rounded-2xl w-full max-w-2xl shadow-2xl max-h-[90vh] overflow-y-auto">
            <h3 className="font-bold text-xl mb-6">
              {isEditing ? 'Editar Proveedor' : 'Registro de Proveedor'}
            </h3>

            {/* Sección: Datos del Proveedor */}
            <div className="bg-blue-50 p-4 rounded-lg mb-4">
              <h4 className="font-bold text-blue-700 mb-3 flex items-center gap-2">
                <User size={18} /> Datos del Proveedor
              </h4>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                <div>
                  <label className="text-xs font-bold text-stone-600">Nombre Completo <span className="text-red-500">*</span></label>
                  <input
                    className="w-full p-2 border rounded-lg mt-1"
                    placeholder="Ej: Juan Pérez"
                    value={form.nombre_completo}
                    onChange={e => setForm({ ...form, nombre_completo: e.target.value })}
                  />
                </div>
                <div>
                  <label className="text-xs font-bold text-stone-600">CI / NIT <span className="text-red-500">*</span></label>
                  <input
                    className="w-full p-2 border rounded-lg mt-1"
                    placeholder="Ej: 123456789"
                    value={form.ci_nit}
                    onChange={e => setForm({ ...form, ci_nit: e.target.value })}
                  />
                </div>
                <div>
                  <label className="text-xs font-bold text-stone-600">Tipo de Proveedor</label>
                  <select
                    className="w-full p-2 border rounded-lg bg-white mt-1"
                    value={form.tipo_proveedor}
                    onChange={e => setForm({ ...form, tipo_proveedor: e.target.value })}
                  >
                    <option value="productor">Productor</option>
                    <option value="cooperativa">Cooperativa</option>
                    <option value="importador">Importador</option>
                  </select>
                </div>
              </div>
            </div>

            {/* Sección: Datos de la Finca */}
            <div className="bg-emerald-50 p-4 rounded-lg mb-4">
              <h4 className="font-bold text-emerald-700 mb-3 flex items-center gap-2">
                <MapPin size={18} /> Datos de la Finca
              </h4>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                <div className="md:col-span-2">
                  <label className="text-xs font-bold text-stone-600">Nombre de la Finca <span className="text-red-500">*</span></label>
                  <input
                    className="w-full p-2 border rounded-lg mt-1"
                    placeholder="Ej: La Esperanza"
                    value={form.nombre_finca}
                    onChange={e => setForm({ ...form, nombre_finca: e.target.value })}
                  />
                </div>
                <div>
                  <label className="text-xs font-bold text-stone-600">País</label>
                  <input
                    className="w-full p-2 border rounded-lg mt-1"
                    placeholder="Bolivia"
                    value={form.pais}
                    onChange={e => setForm({ ...form, pais: e.target.value })}
                  />
                </div>
                <div>
                  <label className="text-xs font-bold text-stone-600">Región</label>
                  <input
                    className="w-full p-2 border rounded-lg mt-1"
                    placeholder="La Paz"
                    value={form.region}
                    onChange={e => setForm({ ...form, region: e.target.value })}
                  />
                </div>
                <div>
                  <label className="text-xs font-bold text-stone-600">Municipio/Zona</label>
                  <input
                    className="w-full p-2 border rounded-lg mt-1"
                    placeholder="Opcional"
                    value={form.sub_region}
                    onChange={e => setForm({ ...form, sub_region: e.target.value })}
                  />
                </div>
                <div>
                  <label className="text-xs font-bold text-stone-600">Altura (msnm)</label>
                  <input
                    className="w-full p-2 border rounded-lg mt-1"
                    type="number"
                    placeholder="1500"
                    value={form.altura_msnm}
                    onChange={e => setForm({ ...form, altura_msnm: e.target.value })}
                  />
                </div>

                {/* Selector de Mapa */}
                <div className="md:col-span-2 mt-3">
                  <MapPicker
                    value={mapCoords}
                    onChange={setMapCoords}
                  />
                </div>
              </div>
            </div>

            <div className="flex gap-3 mt-6">
              <button
                onClick={() => {
                  setShowModal(false);
                  setIsEditing(false);
                  setEditingIds(null);
                  setMapCoords(null);
                }}
                disabled={isLoading}
                className="flex-1 py-3 text-stone-500 font-bold border rounded-xl hover:bg-stone-50 transition-colors disabled:opacity-50"
              >
                Cancelar
              </button>
              <button
                onClick={handleSave}
                disabled={isLoading}
                className="flex-1 py-3 bg-stone-900 text-white rounded-xl font-bold hover:bg-black transition-colors disabled:opacity-50 flex items-center justify-center gap-2"
              >
                {isLoading ? (
                  <><Loader2 className="animate-spin" size={18} /> {isEditing ? 'Actualizando...' : 'Guardando...'}</>
                ) : (
                  isEditing ? 'Actualizar Ficha' : 'Guardar Ficha'
                )}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '../hooks/useAuth';
import { getProveedores, ProveedorPlano } from '../services/proveedoresService';
import { crearLote, LoteForm } from '../services/lotesService';
import { toast } from 'sonner';
import { Warehouse, Save, Search, CheckCircle, MapPin, User, X } from 'lucide-react';
import { Input, Button } from '../components/ui';

export function Recepcion() {
  const { orgId } = useAuth();
  const [proveedores, setProveedores] = useState<ProveedorPlano[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [busquedaProveedor, setBusquedaProveedor] = useState('');
  const [mostrarResultados, setMostrarResultados] = useState(false);
  const [proveedorSeleccionado, setProveedorSeleccionado] = useState<ProveedorPlano | null>(null);
  const wrapperRef = useRef<HTMLDivElement>(null);

  const [form, setForm] = useState<LoteForm>({
    finca_id: '', fecha_compra: new Date().toISOString().split('T')[0],
    peso: '', precio_total: '', estado: 'pergamino_seco', variedad: '', proceso: '', humedad: '', notas: ''
  });

  useEffect(() => {
    if (orgId) getProveedores().then(setProveedores);
  }, [orgId]);

  // Cerrar resultados al hacer clic fuera
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setMostrarResultados(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSave = async () => {
    if (!form.finca_id || !form.peso) return toast.warning("Datos incompletos");

    setIsLoading(true);
    try {
      await crearLote(form, orgId!);
      toast.success("Lote ingresado al almacén");

      // Limpieza completa del formulario
      setForm({
        finca_id: '',
        fecha_compra: new Date().toISOString().split('T')[0],
        peso: '',
        precio_total: '',
        estado: 'pergamino_seco',
        variedad: '',
        proceso: '',
        humedad: '',
        notas: ''
      });
      setProveedorSeleccionado(null);
      setBusquedaProveedor('');
    } catch (e: any) {
      toast.error(e.message);
    } finally {
      setIsLoading(false);
    }
  };

  const seleccionarProveedor = (proveedor: ProveedorPlano) => {
    setProveedorSeleccionado(proveedor);
    setForm({ ...form, finca_id: proveedor.finca_id || proveedor.id });
    setBusquedaProveedor(proveedor.nombre_mostrar);
    setMostrarResultados(false);
  };

  const limpiarProveedor = () => {
    setProveedorSeleccionado(null);
    setForm({ ...form, finca_id: '' });
    setBusquedaProveedor('');
  };

  // Filtrar proveedores solo con finca
  const proveedoresConFinca = proveedores.filter(p => p.finca_id);
  const proveedoresFiltrados = proveedoresConFinca.filter(p =>
    p.nombre_mostrar.toLowerCase().includes(busquedaProveedor.toLowerCase())
  );

  return (
    <div className="max-w-4xl mx-auto p-6">
      <h1 className="text-2xl font-bold text-stone-800 mb-6 flex items-center gap-2">
        <Warehouse className="text-emerald-700" /> Recepción de Café
      </h1>

      <div className="bg-white p-6 rounded-2xl shadow-lg border border-stone-100 space-y-6">

        {/* Búsqueda de Proveedor */}
        <div>
          <label className="font-bold text-sm text-stone-500 mb-2 block">
            Origen (Finca/Productor) <span className="text-red-500">*</span>
          </label>

          <div ref={wrapperRef} className="relative">
            <div className="relative">
              <Search className="absolute left-3 top-3.5 text-stone-400" size={20} />
              <input
                className="w-full pl-10 pr-10 p-3 border-2 border-stone-200 rounded-xl outline-none focus:border-emerald-500 transition-colors"
                placeholder="Buscar proveedor o finca..."
                value={busquedaProveedor}
                onChange={e => {
                  setBusquedaProveedor(e.target.value);
                  setMostrarResultados(true);
                  if (!e.target.value) setProveedorSeleccionado(null);
                }}
                onFocus={() => setMostrarResultados(true)}
              />
              {proveedorSeleccionado && (
                <button
                  onClick={limpiarProveedor}
                  className="absolute right-3 top-3.5 text-stone-400 hover:text-red-500 transition-colors"
                >
                  <X size={20} />
                </button>
              )}
            </div>

            {/* Resultados de búsqueda */}
            {mostrarResultados && busquedaProveedor && (
              <div className="absolute z-50 w-full mt-2 bg-white border-2 border-stone-200 rounded-xl shadow-xl max-h-64 overflow-y-auto">
                {proveedoresFiltrados.length === 0 ? (
                  <div className="p-4 text-center text-stone-400">
                    <p className="text-sm">No se encontraron proveedores</p>
                    <p className="text-xs mt-1">Intenta con otro término de búsqueda</p>
                  </div>
                ) : (
                  proveedoresFiltrados.map(p => {
                    const [proveedor, finca] = p.nombre_mostrar.split(' - ');
                    return (
                      <button
                        key={p.finca_id || p.id}
                        onClick={() => seleccionarProveedor(p)}
                        className="w-full text-left p-3 hover:bg-emerald-50 border-b border-stone-100 last:border-b-0 transition-colors"
                      >
                        <div className="flex items-start gap-2">
                          <User size={16} className="text-stone-400 mt-0.5 flex-shrink-0" />
                          <div className="flex-1 min-w-0">
                            <p className="font-bold text-stone-800 truncate">{proveedor}</p>
                            {finca && (
                              <p className="text-xs text-emerald-600 flex items-center gap-1 mt-0.5">
                                <MapPin size={12} />
                                {finca}
                              </p>
                            )}
                          </div>
                        </div>
                      </button>
                    );
                  })
                )}
              </div>
            )}
          </div>

          {/* Proveedor seleccionado */}
          {proveedorSeleccionado && (
            <div className="mt-3 p-3 bg-emerald-50 border border-emerald-200 rounded-xl flex items-center gap-2">
              <CheckCircle size={18} className="text-emerald-600 flex-shrink-0" />
              <div className="flex-1">
                <p className="text-sm font-bold text-emerald-800">{proveedorSeleccionado.nombre_mostrar}</p>
              </div>
            </div>
          )}

          <p className="text-xs text-stone-400 mt-2">
            {proveedoresConFinca.length} proveedores disponibles
          </p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <Input
            label="Variedad"
            value={form.variedad}
            onChange={e => setForm({ ...form, variedad: e.target.value })}
            placeholder="Ej: Caturra, Geisha, Bourbon"
            hint="Especifica la variedad del café recibido"
          />
          <Input
            label="Proceso"
            value={form.proceso}
            onChange={e => setForm({ ...form, proceso: e.target.value })}
            placeholder="Ej: Lavado, Natural, Honey"
            hint="Método de procesamiento del café"
          />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <label className="font-bold text-sm text-stone-500 mb-2 block">Estado Ingreso</label>
            <select
              className="w-full p-3 border-2 border-stone-200 rounded-xl bg-white focus:border-emerald-500 outline-none transition-colors"
              value={form.estado}
              onChange={e => setForm({ ...form, estado: e.target.value })}
            >
              <option value="cereza">Cereza</option>
              <option value="pergamino_humedo">Pergamino Húmedo</option>
              <option value="pergamino_seco">Pergamino Seco</option>
              <option value="oro_verde">Oro Verde</option>
              <option value="inferior">Inferior/Descarte</option>
            </select>
          </div>

          <Input
            label="Peso (Kg)"
            type="number"
            value={form.peso}
            onChange={e => setForm({ ...form, peso: e.target.value })}
            placeholder="0.0"
            required
            error={form.peso && Number(form.peso) <= 0 ? 'El peso debe ser mayor a 0' : ''}
            className="font-bold text-lg"
          />
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <Input
            label="Precio Total (Bs)"
            type="number"
            value={form.precio_total}
            onChange={e => setForm({ ...form, precio_total: e.target.value })}
            placeholder="0.00"
            hint="Monto pagado por este lote"
          />

          <Input
            label="% Humedad"
            type="number"
            value={form.humedad}
            onChange={e => setForm({ ...form, humedad: e.target.value })}
            placeholder="12.5"
            hint="Nivel de humedad del café (opcional)"
          />
        </div>

        <div>
          <label className="font-bold text-sm text-stone-500 mb-2 block">Notas / Observaciones</label>
          <textarea
            className="w-full p-3 border-2 border-stone-200 rounded-xl focus:border-emerald-500 outline-none transition-colors resize-none"
            rows={3}
            value={form.notas}
            onChange={e => setForm({ ...form, notas: e.target.value })}
            placeholder="Ej: Calidad excepcional, aroma a chocolate..."
          />
        </div>

        <Button
          onClick={handleSave}
          isLoading={isLoading}
          icon={Save}
          variant="primary"
          size="lg"
          fullWidth
          disabled={!form.finca_id || !form.peso}
        >
          Registrar Entrada
        </Button>
      </div>
    </div>
  );
}

import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { toast } from 'sonner';
import { supabase } from '../services/supabaseClient';
import { Mail, ArrowLeft, Send } from 'lucide-react';

export function RecuperarPassword() {
  const [email, setEmail] = useState('');
  const [loading, setLoading] = useState(false);

  const handleRecover = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      const { error } = await supabase.auth.resetPasswordForEmail(email, {
        redirectTo: `${window.location.origin}/restablecer-password`,
      });
      if (error) throw error;
      toast.success('Correo enviado', { description: 'Revisa tu bandeja de entrada.' });
    } catch (error: any) {
      toast.error('Error', { description: error.message });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-stone-50 flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-md p-8 rounded-2xl shadow-xl">
        <Link to="/login" className="flex items-center gap-2 text-stone-400 hover:text-stone-800 mb-6 text-sm font-bold">
          <ArrowLeft size={16}/> Volver
        </Link>
        <h2 className="text-2xl font-bold text-stone-800 mb-2">Recuperar Acceso</h2>
        <p className="text-stone-500 mb-6 text-sm">Te enviaremos un enlace mágico para restablecer tu contraseña.</p>
        
        <form onSubmit={handleRecover} className="space-y-4">
          <div className="relative">
            <Mail className="absolute left-3 top-3 text-stone-400" size={18} />
            <input 
              type="email" 
              className="w-full pl-10 p-3 border rounded-xl outline-none focus:border-emerald-500"
              placeholder="tu@email.com"
              value={email}
              onChange={e => setEmail(e.target.value)}
              required
            />
          </div>
          <button disabled={loading} className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-3 rounded-xl flex justify-center items-center gap-2 transition-all">
            <Send size={18}/> {loading ? 'Enviando...' : 'Enviar Enlace'}
          </button>
        </form>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { toast } from 'sonner';
import { supabase } from '../services/supabaseClient';
import { Coffee, ArrowRight, Loader2, CheckCircle } from 'lucide-react';
import { RegisterSchema, RegisterFormData } from '../utils/validationSchemas';

export function Registro() {
  const navigate = useNavigate();
  const [step, setStep] = useState(1);

  const {
    register,
    handleSubmit,
    trigger,
    formState: { errors, isSubmitting }
  } = useForm<RegisterFormData>({
    resolver: zodResolver(RegisterSchema),
    mode: 'onChange'
  });

  const handleNextStep = async () => {
    // Validar solo campos del paso 1 antes de avanzar
    const isValid = await trigger(['firstName', 'lastName', 'email', 'password']);
    if (isValid) {
      setStep(2);
    }
  };

  const onSubmit = async (formData: RegisterFormData) => {
    try {
      const { error: authError } = await supabase.auth.signUp({
        email: formData.email,
        password: formData.password,
        options: {
          data: {
            first_name: formData.firstName,
            last_name: formData.lastName,
            role: 'administrador',
            org_name: formData.orgName,
            tax_id: formData.nit
          }
        }
      });

      if (authError) throw authError;

      toast.success("¡Cuenta creada con éxito!");
      navigate('/');

    } catch (error: any) {
      console.error(error);
      toast.error('Error en el registro', { description: error.message });
    }
  };

  return (
    <div className="min-h-screen bg-stone-50 flex flex-col items-center justify-center p-4">
      <div className="mb-8 text-center">
        <div className="w-16 h-16 bg-emerald-700 rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-xl shadow-emerald-900/20">
          <Coffee size={32} className="text-white" />
        </div>
        <h1 className="text-3xl font-bold text-stone-900">Comienza tu Prueba Gratis</h1>
        <p className="text-stone-500 mt-2">Gestiona tu tostaduría como un profesional.</p>
      </div>

      <div className="bg-white w-full max-w-lg rounded-3xl shadow-xl overflow-hidden border border-stone-100">
        <div className="h-1 bg-stone-100 w-full">
          <div className={`h-full bg-emerald-600 transition-all duration-500 ${step === 1 ? 'w-1/2' : 'w-full'}`}></div>
        </div>

        <div className="p-8">
          {step === 1 ? (
            <div key="step-1" className="space-y-4 animate-in fade-in slide-in-from-right-4">
              <h2 className="text-xl font-bold text-stone-800 mb-4">1. Tus Datos</h2>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <input
                    className={`p-3 border rounded-xl w-full ${errors.firstName ? 'border-red-500' : ''}`}
                    placeholder="Nombre"
                    autoComplete="given-name"
                    {...register('firstName')}
                  />
                  {errors.firstName && <p className="text-red-500 text-xs ml-1">{errors.firstName.message}</p>}
                </div>
                <div>
                  <input
                    className={`p-3 border rounded-xl w-full ${errors.lastName ? 'border-red-500' : ''}`}
                    placeholder="Apellido"
                    autoComplete="family-name"
                    {...register('lastName')}
                  />
                  {errors.lastName && <p className="text-red-500 text-xs ml-1">{errors.lastName.message}</p>}
                </div>
              </div>

              <div>
                <input
                  type="email"
                  className={`p-3 border rounded-xl w-full ${errors.email ? 'border-red-500' : ''}`}
                  placeholder="Correo Electrónico"
                  autoComplete="email"
                  {...register('email')}
                />
                {errors.email && <p className="text-red-500 text-xs ml-1">{errors.email.message}</p>}
              </div>

              <div>
                <input
                  type="password"
                  className={`p-3 border rounded-xl w-full ${errors.password ? 'border-red-500' : ''}`}
                  placeholder="Contraseña segura"
                  autoComplete="new-password"
                  {...register('password')}
                />
                {errors.password && <p className="text-red-500 text-xs ml-1">{errors.password.message}</p>}
              </div>

              <button
                type="button"
                onClick={handleNextStep}
                className="w-full bg-stone-900 text-white py-3 rounded-xl font-bold mt-4 flex justify-center items-center gap-2 hover:bg-black transition-all"
              >
                Siguiente <ArrowRight size={18} />
              </button>
            </div>
          ) : (
            <div key="step-2" className="space-y-4 animate-in fade-in slide-in-from-right-4">
              <h2 className="text-xl font-bold text-stone-800 mb-4">2. Tu Tostaduría</h2>

              <div>
                <input
                  key="orgName-input"
                  className={`p-3 border rounded-xl w-full ${errors.orgName ? 'border-red-500' : ''}`}
                  placeholder="Nombre de la Empresa"
                  autoComplete="organization"
                  {...register('orgName')}
                />
                {errors.orgName && <p className="text-red-500 text-xs ml-1">{errors.orgName.message}</p>}
              </div>

              <div>
                <input
                  key="nit-input"
                  className="p-3 border rounded-xl w-full"
                  placeholder="NIT / Tax ID (Opcional)"
                  autoComplete="off"
                  {...register('nit')}
                />
              </div>

              <div className="bg-emerald-50 p-4 rounded-xl border border-emerald-100 flex gap-3 items-start">
                <CheckCircle className="text-emerald-600 shrink-0 mt-0.5" size={18} />
                <div className="text-sm text-emerald-800">
                  <p className="font-bold">Plan Prueba 14 Días</p>
                  <p className="opacity-80">Acceso total a todos los módulos. Sin compromiso.</p>
                </div>
              </div>

              <div className="flex gap-3 pt-2">
                <button
                  type="button"
                  onClick={() => setStep(1)}
                  className="px-4 py-3 text-stone-500 font-bold hover:bg-stone-50 rounded-xl transition-colors"
                >
                  Volver
                </button>
                <button
                  onClick={handleSubmit(onSubmit)}
                  disabled={isSubmitting}
                  className="flex-1 bg-emerald-600 text-white py-3 rounded-xl font-bold flex justify-center items-center gap-2 hover:bg-emerald-700 disabled:opacity-50 transition-all shadow-lg shadow-emerald-200"
                >
                  {isSubmitting ? <Loader2 className="animate-spin" /> : 'Crear mi Cuenta'}
                </button>
              </div>
            </div>
          )}
        </div>

        <div className="bg-stone-50 p-4 text-center border-t border-stone-100">
          <p className="text-sm text-stone-500">
            ¿Ya tienes cuenta? <Link to="/login" className="text-stone-900 font-bold hover:underline">Iniciar Sesión</Link>
          </p>
        </div>
      </div>
    </div>
  );
}

import React, { useState } from 'react';
import { useAuth } from '../hooks/useAuth';
import { FiltrosReporte, TipoReporte } from '../components/reportes/FiltrosReporte';
import { ReporteTabla } from '../components/reportes/ReporteTabla';
import { TendenciasChart } from '../components/reportes/TendenciasChart';
import {
  getSalesReport,
  getTopProducts,
  getProductSeasonality,
  getFinancialComparison
} from '../services/reportesService';
import { toast } from 'sonner';

export function Reportes() {
  const { orgId } = useAuth();
  const [tipoReporte, setTipoReporte] = useState<TipoReporte>('ventas');
  const [fechaInicio, setFechaInicio] = useState('');
  const [fechaFin, setFechaFin] = useState('');
  const [loading, setLoading] = useState(false);
  const [datosTabla, setDatosTabla] = useState<any[]>([]);
  const [datosGrafica, setDatosGrafica] = useState<any[]>([]);

  const generarReporte = async () => {
    if (!orgId || !fechaInicio || !fechaFin) {
      toast.error('Por favor completa todos los campos');
      return;
    }

    setLoading(true);
    try {
      switch (tipoReporte) {
        case 'ventas':
          await generarReporteVentas();
          break;
        case 'produccion':
          await generarReporteProduccion();
          break;
        case 'gastos':
          await generarReporteGastos();
          break;
        case 'productos':
          await generarReporteProductos();
          break;
      }
      toast.success('Reporte generado exitosamente');
    } catch (error) {
      console.error('Error generando reporte:', error);
      toast.error('Error al generar reporte');
    } finally {
      setLoading(false);
    }
  };

  const generarReporteVentas = async () => {
    const datos = await getSalesReport(orgId!, fechaInicio, fechaFin, 'month');
    setDatosTabla(datos);
    setDatosGrafica(datos.map(d => ({
      mes: d.label,
      ingreso: Number(d.total_revenue)
    })));
  };

  const generarReporteProduccion = async () => {
    // Por ahora mostrar mensaje
    toast('Vista de producción en construcción', { icon: '🚧' });
    setDatosTabla([]);
    setDatosGrafica([]);
  };

  const generarReporteGastos = async () => {
    const datos = await getFinancialComparison(orgId!, 12);
    const filtrados = datos.filter(d => {
      const fecha = new Date(d.month);
      return fecha >= new Date(fechaInicio) && fecha <= new Date(fechaFin);
    });

    setDatosTabla(filtrados);
    setDatosGrafica(filtrados.map(d => ({
      mes: d.month_label,
      gastos: Number(d.expenses),
      ingresos: Number(d.revenue)
    })));
  };

  const generarReporteProductos = async () => {
    const topProductos = await getTopProducts(orgId!, 10, 90);
    const estacionalidad = await getProductSeasonality(orgId!);

    setDatosTabla(topProductos);

    // Agrupar estacionalidad por mes
    const porMes = estacionalidad.reduce((acc: any, curr) => {
      const mes = curr.month_name.trim();
      if (!acc[mes]) {
        acc[mes] = { mes, cantidad: 0 };
      }
      acc[mes].cantidad += Number(curr.quantity_sold);
      return acc;
    }, {});

    setDatosGrafica(Object.values(porMes));
  };

  const exportarCSV = () => {
    if (datosTabla.length === 0) {
      toast.error('No hay datos para exportar');
      return;
    }

    const headers = Object.keys(datosTabla[0]).join(',');
    const rows = datosTabla.map(fila =>
      Object.values(fila).join(',')
    ).join('\n');

    const csv = `${headers}\n${rows}`;
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `reporte_${tipoReporte}_${new Date().toISOString().split('T')[0]}.csv`;
    a.click();

    toast.success('Reporte exportado');
  };

  // Configuración de columnas según tipo de reporte
  const getColumnas = () => {
    switch (tipoReporte) {
      case 'ventas':
        return [
          { key: 'label', label: 'Período' },
          { key: 'total_orders', label: 'Órdenes', formato: 'numero' },
          { key: 'total_revenue', label: 'Ingresos', formato: 'moneda' },
          { key: 'avg_ticket', label: 'Ticket Prom.', formato: 'moneda' }
        ];
      case 'gastos':
        return [
          { key: 'month_label', label: 'Mes' },
          { key: 'revenue', label: 'Ingresos', formato: 'moneda' },
          { key: 'expenses', label: 'Gastos', formato: 'moneda' },
          { key: 'net_profit', label: 'Ganancia', formato: 'moneda' },
          { key: 'profit_margin_percentage', label: 'Margen %', formato: 'porcentaje' }
        ];
      case 'productos':
        return [
          { key: 'rank', label: '#' },
          { key: 'product_name', label: 'Producto' },
          { key: 'category', label: 'Categoría' },
          { key: 'quantity_sold', label: 'Vendidos', formato: 'numero' },
          { key: 'revenue', label: 'Ingresos', formato: 'moneda' },
          { key: 'times_ordered', label: 'Pedidos', formato: 'numero' }
        ];
      default:
        return [];
    }
  };

  const getTituloTabla = () => {
    const titulos = {
      ventas: 'Reporte de Ventas',
      produccion: 'Reporte de Producción',
      gastos: 'Comparativo Financiero',
      productos: 'Top Productos Más Vendidos'
    };
    return titulos[tipoReporte];
  };

  const getTituloGrafica = () => {
    const titulos = {
      ventas: 'Tendencia de Ingresos',
      produccion: 'Producción Mensual',
      gastos: 'Ingresos vs Gastos',
      productos: 'Ventas por Mes'
    };
    return titulos[tipoReporte];
  };

  return (
    <div className="p-6 max-w-7xl mx-auto space-y-6">
      {/* Header */}
      <div>
        <h1 className="text-3xl font-bold text-stone-800">📊 Reportes y Análisis</h1>
        <p className="text-stone-500 mt-1">
          Genera reportes personalizados y analiza tendencias
        </p>
      </div>

      {/* Filtros */}
      <FiltrosReporte
        tipoReporte={tipoReporte}
        onTipoChange={setTipoReporte}
        fechaInicio={fechaInicio}
        fechaFin={fechaFin}
        onFechaInicioChange={setFechaInicio}
        onFechaFinChange={setFechaFin}
        onGenerar={generarReporte}
        loading={loading}
      />

      {/* Gráfica */}
      {datosGrafica.length > 0 && (
        <TendenciasChart
          titulo={getTituloGrafica()}
          datos={datosGrafica}
          dataKeyX={tipoReporte === 'productos' ? 'mes' : 'mes'}
          dataKeyY={tipoReporte === 'ventas' ? 'ingreso' : tipoReporte === 'gastos' ? 'ingresos' : 'cantidad'}
          labelY={tipoReporte === 'ventas' ? 'Ingresos (Bs)' : tipoReporte === 'gastos' ? 'Monto (Bs)' : 'Cantidad'}
          tipo={tipoReporte === 'productos' ? 'barra' : 'linea'}
          loading={loading}
        />
      )}

      {/* Tabla */}
      {datosTabla.length > 0 && (
        <ReporteTabla
          titulo={getTituloTabla()}
          columnas={getColumnas()}
          datos={datosTabla}
          loading={loading}
          onExportar={exportarCSV}
        />
      )}

      {/* Estado vacío inicial */}
      {!loading && datosTabla.length === 0 && datosGrafica.length === 0 && (
        <div className="bg-white p-12 rounded-xl border border-stone-200 text-center">
          <div className="text-6xl mb-4">📊</div>
          <h3 className="text-xl font-bold text-stone-800 mb-2">
            Selecciona un período y genera tu reporte
          </h3>
          <p className="text-stone-500">
            Elige el tipo de reporte, las fechas y haz clic en "Generar Reporte"
          </p>
        </div>
      )}
    </div>
  );
}

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { toast } from 'sonner';
import { supabase } from '../services/supabaseClient';
import { Lock, CheckCircle } from 'lucide-react';

export function RestablecerPassword() {
  const navigate = useNavigate();
  const [pass, setPass] = useState('');
  const [loading, setLoading] = useState(false);

  const handleUpdate = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      const { error } = await supabase.auth.updateUser({ password: pass });
      if (error) throw error;
      toast.success('Contraseña actualizada');
      navigate('/');
    } catch (error: any) {
      toast.error('Error', { description: error.message });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-stone-50 flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-md p-8 rounded-2xl shadow-xl">
        <h2 className="text-2xl font-bold text-stone-800 mb-6">Nueva Contraseña</h2>
        <form onSubmit={handleUpdate} className="space-y-4">
          <div className="relative">
            <Lock className="absolute left-3 top-3 text-stone-400" size={18} />
            <input 
              type="password" 
              className="w-full pl-10 p-3 border rounded-xl outline-none focus:border-emerald-500"
              placeholder="Nueva contraseña segura"
              value={pass}
              onChange={e => setPass(e.target.value)}
              required
              minLength={6}
            />
          </div>
          <button disabled={loading} className="w-full bg-stone-900 text-white font-bold py-3 rounded-xl flex justify-center items-center gap-2">
            <CheckCircle size={18}/> Actualizar
          </button>
        </form>
      </div>
    </div>
  );
}

