import { supabase } from './supabaseClient';
import { Database } from '../types/supabase';

// Extraemos el tipo de fila de 'profiles' directamente de tu archivo generado
type ProfileRow = Database['public']['Tables']['profiles']['Row'];

// Definimos la interfaz de lo que devuelve TU función (mezcla Auth + Base de datos)
export interface UserProfile {
  id: string;
  email: string | undefined;
  organization_id: string | null;
  role: string | null; // El tipo generado probablemente sea un string o un enum
  first_name: string | null;
}

export const getUserProfile = async (): Promise<UserProfile | null> => {
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return null;

  // Como ya conectamos el cliente, TypeScript sabe que 'profiles' existe
  const { data, error } = await supabase
    .from('profiles')
    .select('organization_id, role, first_name') // TS validará que estos campos existan
    .eq('id', user.id)
    .single();

  if (error || !data) {
    console.error("Error fetching profile:", error);
    return null;
  }
  
  return { 
    id: user.id, 
    email: user.email,
    organization_id: data.organization_id,
    role: data.role,
    first_name: data.first_name
  };
};

export const getCurrentOrgId = async (): Promise<string> => {
  const profile = await getUserProfile();
  // Validamos explícitamente porque organization_id puede ser null en la BD
  if (!profile?.organization_id) {
    throw new Error("No tienes una organización asignada.");
  }
  return profile.organization_id;
};

export const getCurrentUserId = async (): Promise<string | undefined> => {
  const { data: { user } } = await supabase.auth.getUser();
  return user?.id;
};

import { supabase } from './supabaseClient';

export interface CierreData {
  system_cash: number;
  system_qr: number;
  system_card: number;
  declared_cash: number;
  declared_qr: number;
  declared_card: number;
  cash_withdrawals: number;
  notes: string;
}

export interface CierreHistorico {
  id: string;
  user_id: string;
  user_name: string;
  opened_at: string;
  closed_at: string;
  initial_cash: number;
  system_cash: number;
  system_qr: number;
  system_card: number;
  declared_cash: number;
  declared_qr: number;
  declared_card: number;
  cash_withdrawals: number;
  difference: number;
  notes: string | null;
  sales_count: number;
}

export interface DetalleCierre {
  cierre: CierreHistorico;
  ventas: {
    efectivo: { total: number; count: number };
    qr: { total: number; count: number };
    tarjeta: { total: number; count: number };
  };
}

export const registrarApertura = async (montoInicial: number, orgId: string, userId: string) => {
  const { data, error } = await supabase
    .from('cash_openings')
    .insert([{
      organization_id: orgId,
      user_id: userId,
      initial_cash: montoInicial,
      opened_at: new Date().toISOString()
    }])
    .select()
    .single();

  if (error) throw error;
  return data;
};

export const verificarEstadoCaja = async (orgId: string, userId: string) => {
  const { data, error } = await supabase.rpc('get_cash_status', {
    p_org_id: orgId,
    p_user_id: userId
  });
  if (error) throw error;
  return data; // { status: 'open' | 'closed', ... }
};

export const obtenerResumenCaja = async (orgId: string, userId: string) => {
  const { data, error } = await supabase.rpc('get_pending_cash_summary', {
