};

export const registrarCierre = async (datos: CierreData, orgId: string, userId: string) => {
  // El total del sistema es el efectivo inicial + ventas efectivo
  const totalSystem = datos.system_cash + datos.system_qr + datos.system_card;
  const totalDeclared = (datos.declared_cash + datos.cash_withdrawals) + datos.declared_qr + datos.declared_card;
  const difference = totalDeclared - totalSystem;

  const { data, error } = await supabase
    .from('cash_closures')
    .insert([{
      organization_id: orgId,
      user_id: userId,
      system_cash: datos.system_cash,
      system_qr: datos.system_qr,
      system_card: datos.system_card,
      declared_cash: datos.declared_cash,
      declared_qr: datos.declared_qr,
      declared_card: datos.declared_card,
      cash_withdrawals: datos.cash_withdrawals,
      difference: difference,
      notes: datos.notes,
      closed_at: new Date().toISOString()
    }])
    .select()
    .single();

  if (error) throw error;
  return data;
};

export const getCierresHistorico = async (orgId: string, filtros?: { fechaDesde?: string; fechaHasta?: string; userId?: string }) => {
  let query = supabase
    .from('cash_closures')
    .select(`
      id,
      user_id,
      closed_at,
      system_cash,
      system_qr,
      system_card,
      declared_cash,
      declared_qr,
      declared_card,
      cash_withdrawals,
      difference,
      notes
    `)
    .eq('organization_id', orgId)
    .order('closed_at', { ascending: false });

  // Aplicar filtros opcionales
  if (filtros?.fechaDesde) {
    query = query.gte('closed_at', filtros.fechaDesde);
  }
  if (filtros?.fechaHasta) {
    query = query.lte('closed_at', filtros.fechaHasta);
  }
  if (filtros?.userId) {
    query = query.eq('user_id', filtros.userId);
  }

  const { data: cierres, error } = await query;
  if (error) throw error;

  // Obtener información de usuario y apertura para cada cierre
  const cierresConInfo = await Promise.all(
    (cierres || []).map(async (cierre: any) => {
      // Obtener nombre del usuario
      const { data: usuario } = await supabase
        .from('users')
        .select('first_name, last_name')
        .eq('id', cierre.user_id)
        .single();

      // Obtener apertura más reciente del usuario antes del cierre
      const { data: apertura } = await supabase
        .from('cash_openings')
        .select('initial_cash, opened_at')
        .eq('user_id', cierre.user_id)
        .lte('opened_at', cierre.closed_at)
        .order('opened_at', { ascending: false })
        .limit(1)
        .single();

      // Contar ventas del período
      const { count } = await supabase
        .from('sales_orders')
        .select('*', { count: 'exact', head: true })
        .eq('seller_id', cierre.user_id)
        .gte('order_date', apertura?.opened_at || cierre.closed_at)
        .lte('order_date', cierre.closed_at);

      return {
        id: cierre.id,
        user_id: cierre.user_id,
        user_name: usuario ? `${usuario.first_name} ${usuario.last_name}` : 'Desconocido',
        opened_at: apertura?.opened_at || cierre.closed_at,
        closed_at: cierre.closed_at,
        initial_cash: apertura?.initial_cash || 0,
        system_cash: cierre.system_cash,
        system_qr: cierre.system_qr,
        system_card: cierre.system_card,
        declared_cash: cierre.declared_cash,
        declared_qr: cierre.declared_qr,
        declared_card: cierre.declared_card,
        cash_withdrawals: cierre.cash_withdrawals,
        difference: cierre.difference,
        notes: cierre.notes,
        sales_count: count || 0
      };
    })
  );

  return cierresConInfo as CierreHistorico[];
};

export const getDetalleCierre = async (cierreId: string): Promise<DetalleCierre> => {
  // Obtener cierre
  const { data: cierre, error: cierreError } = await supabase
    .from('cash_closures')
    .select(`
      id,
      user_id,
      closed_at,
      system_cash,
      system_qr,
      system_card,
      declared_cash,
      declared_qr,
      declared_card,
      cash_withdrawals,
      difference,
      notes
    `)
    .eq('id', cierreId)
    .single();

  if (cierreError) throw cierreError;
  if (!cierre) throw new Error('Cierre no encontrado');

  // Obtener usuario
  const { data: usuario } = await supabase
    .from('users')
    .select('first_name, last_name')
    .eq('id', cierre.user_id)
    .single();

  // Obtener apertura
  const { data: apertura } = await supabase
    .from('cash_openings')
    .select('initial_cash, opened_at')
    .eq('user_id', cierre.user_id)
    .lte('opened_at', cierre.closed_at)
    .order('opened_at', { ascending: false })
    .limit(1)
    .single();

  // Obtener ventas del período agrupadas por método de pago
  const { data: ventas } = await supabase
    .from('sales_orders')
    .select('payment_method, total_amount')
    .eq('seller_id', cierre.user_id)
    .eq('status', 'completed')
    .gte('order_date', apertura?.opened_at || cierre.closed_at)
    .lte('order_date', cierre.closed_at);

  // Agrupar ventas por método de pago
  const ventasAgrupadas = {
    efectivo: { total: 0, count: 0 },
    qr: { total: 0, count: 0 },
    tarjeta: { total: 0, count: 0 }
  };

  (ventas || []).forEach((venta: any) => {
    const metodo = venta.payment_method.toLowerCase();
    if (metodo === 'efectivo') {
      ventasAgrupadas.efectivo.total += venta.total_amount;
      ventasAgrupadas.efectivo.count++;
    } else if (metodo === 'qr') {
      ventasAgrupadas.qr.total += venta.total_amount;
      ventasAgrupadas.qr.count++;
    } else if (metodo === 'tarjeta') {
      ventasAgrupadas.tarjeta.total += venta.total_amount;
      ventasAgrupadas.tarjeta.count++;
    }
  });

  const cierreConInfo: CierreHistorico = {
    id: cierre.id,
    user_id: cierre.user_id,
    user_name: usuario ? `${usuario.first_name} ${usuario.last_name}` : 'Desconocido',
    opened_at: apertura?.opened_at || cierre.closed_at,
    closed_at: cierre.closed_at,
    initial_cash: apertura?.initial_cash || 0,
    system_cash: cierre.system_cash,
    system_qr: cierre.system_qr,
    system_card: cierre.system_card,
    declared_cash: cierre.declared_cash,
    declared_qr: cierre.declared_qr,
    declared_card: cierre.declared_card,
    cash_withdrawals: cierre.cash_withdrawals,
    difference: cierre.difference,
    notes: cierre.notes,
    sales_count: (ventas || []).length
  };

  return {
    cierre: cierreConInfo,
    ventas: ventasAgrupadas
  };
};

import { supabase } from './supabaseClient';

export interface DashboardData {
  ventasHoy: number;
  gastosMes: number;
  ventasMes: number;
  transaccionesHoy: number;
  ticketPromedio: number;
  alertasStock: any[];
  actividadReciente: any[];
  progresoMeta: number;
}

export const getDashboardMetrics = async (orgId: string): Promise<DashboardData> => {
  const hoy = new Date().toISOString().split('T')[0];
  const inicioMes = new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString();

  // 1. VENTAS (Hoy y Mes)
  const { data: ventas } = await supabase
    .from('sales_orders')
    .select('total_amount, order_date')
    .eq('organization_id', orgId)
    .gte('order_date', inicioMes);

  // CORRECCIÓN 1: Verificamos que 'v.order_date' exista (&&) antes de usar .startsWith
  const ventasHoyArr = ventas?.filter(v => v.order_date && v.order_date.startsWith(hoy)) || [];
  
  const totalVentasHoy = ventasHoyArr.reduce((sum, v) => sum + v.total_amount, 0);
  const totalVentasMes = ventas?.reduce((sum, v) => sum + v.total_amount, 0) || 0;
  const transacciones = ventasHoyArr.length;
  
  // 2. GASTOS
  const { data: gastos } = await supabase
    .from('expense_ledger')
    .select('amount_paid')
    .eq('organization_id', orgId)
    .gte('payment_date', inicioMes);
  
  const totalGastosReales = gastos?.reduce((sum, g) => sum + g.amount_paid, 0) || 0;
  
  // Meta (Gastos Fijos)
  const { data: fijos } = await supabase.from('fixed_expenses').select('amount').eq('organization_id', orgId).eq('is_active', true);
  const metaGastosFijos = fijos?.reduce((sum, f) => sum + f.amount, 0) || 1000;

  // 3. ALERTAS DE STOCK
  const { data: insumosBajos } = await supabase
    .from('supplies_inventory')
    .select('name, current_stock, unit_measure')
    .eq('organization_id', orgId)
    .lt('current_stock', 10)
    .limit(5);

  const { data: prodBajos } = await supabase
    .from('finished_inventory')
    .select('current_stock, products(name)')
    .eq('organization_id', orgId)
    .lt('current_stock', 5)
    .limit(5);

  const alertas = [
    ...(insumosBajos || []).map(i => ({ 
      tipo: 'insumo', 
      msg: `${i.name} bajo (${i.current_stock} ${i.unit_measure})` 
    })),
    // CORRECCIÓN 2: Usamos p.products?.name (el signo ? evita el error si es null)
    // Además agregamos || 'Producto' por si el nombre viniera vacío.
    ...(prodBajos || []).map(p => ({ 
      tipo: 'producto', 
      msg: `${p.products?.name || 'Producto'} bajo (${p.current_stock} und)` 
    }))
  ];

  // 4. CÁLCULOS FINALES
  const metaDiaria = metaGastosFijos / 30; 
  const progreso = metaDiaria > 0 ? (totalVentasHoy / metaDiaria) * 100 : 0;

  return {
    ventasHoy: totalVentasHoy,
    ventasMes: totalVentasMes,
    gastosMes: totalGastosReales,
    transaccionesHoy: transacciones,
    ticketPromedio: transacciones > 0 ? totalVentasHoy / transacciones : 0,
    alertasStock: alertas,
    actividadReciente: [],
    progresoMeta: Math.min(progreso, 100)
  };
};

