import { supabase } from './supabaseClient';
import { ProveedorFormData } from '../utils/validationSchemas';

export interface ProveedorPlano {
  id: string;
  finca_id: string | null;
  nombre_mostrar: string;
  hasCoordinates?: boolean;
}

export interface ProveedorCompleto {
  supplier: {
    id: string;
    name: string;
    tax_id: string;
    type: 'productor' | 'cooperativa' | 'importador';
  };
  farm: {
    id: string;
    name: string;
    producer_name: string | null;
    country_code: string;
    region: string | null;
    sub_region: string | null;
    altitude_masl: number | null;
    latitude: number | null;
    longitude: number | null;
  };
}

export const crearProveedor = async (formData: ProveedorFormData, orgId: string) => {
  // 1. Insertar Proveedor
  const { data: supplier, error: errSup } = await supabase
    .from('suppliers')
    .insert([{
      organization_id: orgId,
      name: formData.nombre_completo,
      tax_id: formData.ci_nit,
      type: formData.tipo_proveedor as "productor" | "cooperativa" | "importador", // Validado previamente por Zod
    }])
    .select()
    .single();

  if (errSup) throw errSup;
  if (!supplier) throw new Error("Error al crear el proveedor base.");

  // 2. Insertar Finca asociada
  const { error: errFarm } = await supabase
    .from('farms')
    .insert([{
      organization_id: orgId,
      supplier_id: supplier.id,
      name: formData.nombre_finca,
      producer_name: formData.nombre_productor || (formData.tipo_proveedor === 'productor' ? formData.nombre_completo : null),
      country_code: formData.pais,
      region: formData.region,
      sub_region: formData.sub_region || null,
      altitude_masl: formData.altura_msnm,
      latitude: formData.latitude || null,
      longitude: formData.longitude || null
    }]);

  if (errFarm) throw errFarm;
  return true;
};

export const getProveedores = async (): Promise<ProveedorPlano[]> => {
  // Consulta segura con tipos inferidos por Supabase Client
  const { data, error } = await supabase
    .from('suppliers')
    .select(`
      id, 
      name, 
      type, 
      farms ( id, name, region, latitude, longitude )
    `)
    .order('name');

  if (error) throw error;

  // Transformación segura de datos
  const listaPlana: ProveedorPlano[] = [];

  data?.forEach((prov) => {
    // Verificamos si tiene fincas (como array)
    const fincas = prov.farms;

    if (Array.isArray(fincas) && fincas.length > 0) {
      fincas.forEach((finca: any) => {
        listaPlana.push({
          id: prov.id,
          finca_id: finca.id,
          nombre_mostrar: `${prov.name} - ${finca.name} (${finca.region})`,
          hasCoordinates: !!(finca.latitude && finca.longitude)
        });
      });
    } else {
      listaPlana.push({
        id: prov.id,
        finca_id: null,
        nombre_mostrar: `${prov.name} (Sin Finca)`,
        hasCoordinates: false
      });
    }
  });

  return listaPlana;
};

export const getProveedorCompleto = async (supplierId: string, farmId: string): Promise<ProveedorCompleto> => {
  // Obtener datos del proveedor
  const { data: supplier, error: errSupplier } = await supabase
    .from('suppliers')
    .select('id, name, tax_id, type')
    .eq('id', supplierId)
    .single();

  if (errSupplier) throw errSupplier;
  if (!supplier) throw new Error('Proveedor no encontrado');

  // Obtener datos de la finca
  const { data: farm, error: errFarm } = await supabase
    .from('farms')
    .select('id, name, producer_name, country_code, region, sub_region, altitude_masl, latitude, longitude')
    .eq('id', farmId)
    .single();

  if (errFarm) throw errFarm;
  if (!farm) throw new Error('Finca no encontrada');

  return {
    supplier: {
      id: supplier.id,
      name: supplier.name,
      tax_id: supplier.tax_id,
      type: supplier.type as 'productor' | 'cooperativa' | 'importador'
    },
    farm: {
      id: farm.id,
      name: farm.name,
      producer_name: farm.producer_name,
      country_code: farm.country_code,
      region: farm.region,
      sub_region: farm.sub_region,
      altitude_masl: farm.altitude_masl,
      latitude: farm.latitude,
      longitude: farm.longitude
    }
  };
};

export const actualizarProveedor = async (supplierId: string, farmId: string, formData: ProveedorFormData) => {
  // 1. Actualizar datos del proveedor
  const { error: errSupplier } = await supabase
    .from('suppliers')
    .update({
      name: formData.nombre_completo,
      tax_id: formData.ci_nit,
      type: formData.tipo_proveedor as "productor" | "cooperativa" | "importador"
    })
    .eq('id', supplierId);

  if (errSupplier) throw errSupplier;

  // 2. Actualizar datos de la finca
  const { error: errFarm } = await supabase
    .from('farms')
    .update({
      name: formData.nombre_finca,
      producer_name: formData.nombre_productor || (formData.tipo_proveedor === 'productor' ? formData.nombre_completo : null),
      country_code: formData.pais,
      region: formData.region,
      sub_region: formData.sub_region || null,
      altitude_masl: formData.altura_msnm,
      latitude: formData.latitude || null,
      longitude: formData.longitude || null
    })
    .eq('id', farmId);

  if (errFarm) throw errFarm;
  return true;
};

import { supabase } from './supabaseClient';

export interface LoteProyeccion {
  id: string;
  codigo: string;
  origen: string;
  variedad: string | null;
  notas: string;
  stock_actual: number;
  costo_total: number;
  rendimiento_lab: number | null;
}

export const getLotesParaProyeccion = async (orgId: string): Promise<LoteProyeccion[]> => {
  const { data, error } = await supabase
    .from('raw_inventory_batches')
    .select(`
      id, code_ref, current_quantity, total_cost_local, variety, observations, 
      farms ( name ),
      lab_reports ( sample_total_grams, green_quantity )
    `)
    .eq('organization_id', orgId)
    .gt('current_quantity', 0)
    .order('created_at', { ascending: false });

  if (error) throw error;

  return (data || []).map((d: any) => {
    // Calculamos rendimiento real si existe reporte de lab
    let rendimientoReal: number | null = null;
    const reporte = d.lab_reports?.[0];
    
    if (reporte && reporte.sample_total_grams > 0) {
      rendimientoReal = (reporte.green_quantity / reporte.sample_total_grams) * 100;
    }

    return {
      id: d.id,
      codigo: d.code_ref,
      origen: d.farms?.name || 'Desconocido',
      variedad: d.variety,
      notas: d.observations || '',
      stock_actual: d.current_quantity,
      costo_total: d.total_cost_local || 0,
      rendimiento_lab: rendimientoReal
    };
  });
};

import { supabase } from './supabaseClient';
import { Database } from '../types/supabase';

// Tipos para facilitar el uso en la UI
export interface RecetaItem {
  id: string;
  supply_id: string;
  quantity_required: number;
  // Datos del insumo (Join)
  insumo_nombre: string;
  insumo_medida: string;
  insumo_costo: number;
}

export interface ProductoConReceta {
  id: string;
  name: string;
  sale_price: number;
  costo_estimado: number; // Suma de costos de ingredientes
}

// 1. Obtener productos con su costo calculado
export const getProductosParaRecetas = async (orgId: string): Promise<ProductoConReceta[]> => {
  // Traemos productos y sus recetas
  const { data: productos, error } = await (supabase as any)
    .from('products')
    .select(`
      id, name, sale_price,
      product_recipes (
        quantity_required,
        supplies_inventory ( unit_cost )
      )
    `)
    .eq('organization_id', orgId)
    .eq('is_active', true)
    .order('name');

  if (error) throw error;

  // Calculamos el costo total sumando (cantidad * costo_unitario) de cada ingrediente
  return (productos || []).map((p: any) => {
    const costoTotal = p.product_recipes?.reduce((sum: number, r: any) => {
      const cantidad = r.quantity_required || 0;
      const costoUnitario = r.supplies_inventory?.unit_cost || 0;
      return sum + (cantidad * costoUnitario);
    }, 0);

    return {
      id: p.id,
      name: p.name,
      sale_price: p.sale_price || 0,
      costo_estimado: costoTotal
    };
  });
};

// 2. Obtener ingredientes de un producto específico
export const getIngredientesProducto = async (productId: string): Promise<RecetaItem[]> => {
  const { data, error } = await (supabase as any)
    .from('product_recipes')
    .select(`
      id, supply_id, quantity_required,
      supplies_inventory ( name, unit_measure, unit_cost )
    `)
    .eq('product_id', productId);

  if (error) throw error;

  return (data || []).map((r: any) => ({
    id: r.id,
    supply_id: r.supply_id,
    quantity_required: r.quantity_required,
    insumo_nombre: r.supplies_inventory?.name || 'Desconocido',
    insumo_medida: r.supplies_inventory?.unit_measure || '',
    insumo_costo: r.supplies_inventory?.unit_cost || 0
  }));
};

// 3. Agregar Ingrediente
export const agregarIngrediente = async (productId: string, supplyId: string, cantidad: number, condicion: 'always' | 'takeaway' | 'dine_in' = 'always') => {
  const { data, error } = await supabase
    .from('product_recipes')
    .insert([{
      product_id: productId,
      supply_id: supplyId,
      quantity_required: cantidad,
      condition: condicion
    }])
    .select()
    .single();

  if (error) throw error;
  return data;
};

// 4. Eliminar Ingrediente
export const eliminarIngrediente = async (recetaId: string) => {
  const { error } = await supabase
    .from('product_recipes')
    .delete()
    .eq('id', recetaId);
  
  if (error) throw error;
};

import { supabase } from './supabaseClient';

export interface ReporteItem {
  fecha: string;
  hora: string;
  cliente: string;
  vendedor: string;
  metodo_pago: string;
  producto: string;
  cantidad: number;
  precio_unitario: number;
  subtotal: number;
}

export const getReporteVentas = async (fechaInicio: string, fechaFin: string, orgId: string): Promise<ReporteItem[]> => {
  const { data, error } = await supabase
    .from('sales_orders')
    .select(`
      id, order_date, total_amount, payment_method,
      client:clients(business_name),
      seller:profiles(first_name),
      items:sales_order_items (
        quantity, unit_price,
        product:products(name),
        green:green_coffee_warehouse(name_ref)
      )
    `)
    .eq('organization_id', orgId)
    .gte('order_date', fechaInicio)
    .lte('order_date', fechaFin)
    .order('order_date', { ascending: false });

  if (error) throw error;

  let reportePlano: ReporteItem[] = [];

  (data || []).forEach((orden: any) => {
    orden.items.forEach((item: any) => {
      reportePlano.push({
        fecha: new Date(orden.order_date).toLocaleDateString(),
        hora: new Date(orden.order_date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        cliente: orden.client?.business_name || 'Consumidor Final',
        vendedor: orden.seller?.first_name || 'Sistema',
        metodo_pago: orden.payment_method || 'Efectivo',
